{"sections":[{"type":"heading","level":1,"text":"Encapsulation — Đóng Gói"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Encapsulation không chỉ là private fields + getter/setter. Senior cần hiểu information hiding, invariant protection, immutability strategies, và module system (Java 9+) như một cấp độ encapsulation mới."},{"type":"heading","level":2,"text":"Keyword: Encapsulation vs Information Hiding"},{"type":"paragraph","text":"**Định nghĩa:** Encapsulation = bundling data + behavior. Information hiding = ẩn implementation details. Hai khái niệm liên quan nhưng khác nhau."},{"type":"code_block","code":"// Encapsulation WITHOUT information hiding — vô nghĩa
// ❌ Getter/setter cho mọi field = expose toàn bộ internal state
public class User {
    private String name;
    private String email;
    private List<String> roles;

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
    public List<String> getRoles() { return roles; }  // ⚠️ Expose mutable list!
    public void setRoles(List<String> roles) { this.roles = roles; }
}
// Đây chỉ là "encapsulation theater" — không bảo vệ gì cả
// Caller vẫn biết và phụ thuộc vào internal structure

// ✅ True information hiding — expose behavior, hide data
public class User {
    private String name;
    private String email;
    private final Set<Role> roles = EnumSet.noneOf(Role.class);

    // Expose behavior, không expose data structure
    public boolean hasRole(Role role) {
        return roles.contains(role);
    }

    public void grantRole(Role role) {
        Objects.requireNonNull(role);
        roles.add(role);
    }

    public void revokeRole(Role role) {
        roles.remove(role);
    }

    // Nếu cần expose collection → unmodifiable copy
    public Set<Role> getRoles() {
        return Collections.unmodifiableSet(roles);
    }

    // Validate trong setter — protect invariants
    public void setEmail(String email) {
        if (email == null || !email.contains("@")) {
            throw new IllegalArgumentException("Invalid email: " + email);
        }
        this.email = email.toLowerCase().trim();
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Invariant Protection"},{"type":"paragraph","text":"**Định nghĩa:** Đảm bảo object luôn ở trạng thái hợp lệ — không thể tạo hoặc chuyển sang trạng thái invalid."},{"type":"code_block","code":"// Class invariant: điều kiện LUÔN đúng cho mọi instance
// Ví dụ: DateRange — start <= end
public class DateRange {
    private final LocalDate start;
    private final LocalDate end;

    public DateRange(LocalDate start, LocalDate end) {
        Objects.requireNonNull(start, "start");
        Objects.requireNonNull(end, "end");
        if (start.isAfter(end)) {
            throw new IllegalArgumentException("start must be <= end");
        }
        this.start = start;
        this.end = end;
    }

    // Immutable → invariant luôn được bảo vệ
    // Không có setter → không thể phá invariant sau construction
}

// Mutable class — khó bảo vệ invariant hơn
public class BankAccount {
    private BigDecimal balance;
    private boolean frozen;

    // Invariant: balance >= 0, frozen account cannot transact
    public void withdraw(BigDecimal amount) {
        if (frozen) throw new IllegalStateException("Account is frozen");
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            throw new IllegalArgumentException("Amount must be positive");
        }
        if (amount.compareTo(balance) > 0) {
            throw new InsufficientFundsException(balance, amount);
        }
        balance = balance.subtract(amount);
        // Invariant maintained: balance still >= 0
    }

    // Thread safety — synchronized để protect invariant trong concurrent access
    public synchronized void transfer(BankAccount target, BigDecimal amount) {
        this.withdraw(amount);
        target.deposit(amount);
        // Nếu không synchronized: race condition có thể phá invariant
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Immutability Strategies"},{"type":"paragraph","text":"**Định nghĩa:** Các cách tạo immutable objects — từ simple đến deep immutability."},{"type":"code_block","code":"// Level 1: Shallow immutability — final fields, no setters
public final class Money {
    private final BigDecimal amount;
    private final Currency currency;

    public Money(BigDecimal amount, Currency currency) {
        this.amount = Objects.requireNonNull(amount);
        this.currency = Objects.requireNonNull(currency);
    }

    public Money add(Money other) {
        if (!currency.equals(other.currency)) {
            throw new IllegalArgumentException("Currency mismatch");
        }
        return new Money(amount.add(other.amount), currency);
    }
}

// Level 2: Deep immutability — defensive copy cho mutable fields
public final class Event {
    private final String name;
    private final List<String> attendees;
    private final Date timestamp;  // Date is mutable!

    public Event(String name, List<String> attendees, Date timestamp) {
        this.name = name;
        this.attendees = List.copyOf(attendees);  // Immutable copy
        this.timestamp = new Date(timestamp.getTime());  // Defensive copy
    }

    public List<String> getAttendees() {
        return attendees;  // Already immutable — safe to return
    }

    public Date getTimestamp() {
        return new Date(timestamp.getTime());  // Defensive copy on get
    }
}

// Level 3: Record — built-in immutability (Java 16+)
public record Money(BigDecimal amount, Currency currency) {
    public Money {
        Objects.requireNonNull(amount);
        Objects.requireNonNull(currency);
    }
    public Money add(Money other) {
        return new Money(amount.add(other.amount), currency);
    }
}

// Immutable collections (Java 9+)
List<String> immutableList = List.of("a", "b", "c");
Set<Integer> immutableSet = Set.of(1, 2, 3);
Map<String, Integer> immutableMap = Map.of("a", 1, "b", 2);
// Tất cả throw UnsupportedOperationException khi modify

// Collections.unmodifiableXxx — wrapper, không copy
List<String> mutable = new ArrayList<>(List.of("a", "b"));
List<String> unmodifiable = Collections.unmodifiableList(mutable);
mutable.add("c");  // unmodifiable cũng thấy "c"! (chỉ là view)

// List.copyOf — copy, truly independent
List<String> copied = List.copyOf(mutable);
mutable.add("d");  // copied KHÔNG thấy "d"

// Benefits of immutability:
// 1. Thread-safe without synchronization
// 2. Can be shared freely (no defensive copies needed)
// 3. Great as Map keys and Set elements (hashCode stable)
// 4. Easier to reason about (no state changes)
// 5. Failure atomicity (operation fails → object unchanged)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Module System (Java 9+)"},{"type":"paragraph","text":"**Định nghĩa:** Java Platform Module System (JPMS) — encapsulation ở cấp package, mạnh hơn access modifiers."},{"type":"code_block","code":"// module-info.java
module com.example.myapp {
    // Declare dependencies
    requires java.sql;
    requires java.logging;
    requires transitive com.example.common;  // Transitive: callers cũng thấy

    // Export packages — chỉ exported packages visible bên ngoài module
    exports com.example.myapp.api;
    exports com.example.myapp.model;

    // Qualified export — chỉ cho module cụ thể
    exports com.example.myapp.internal to com.example.testing;

    // Open for reflection (Spring, Hibernate cần)
    opens com.example.myapp.model to com.fasterxml.jackson.databind;

    // Service provider
    provides com.example.spi.Plugin with com.example.myapp.MyPlugin;
    uses com.example.spi.Plugin;
}

// Trước modules: public class = accessible everywhere
// Sau modules: public class trong unexported package = KHÔNG accessible
// → Strong encapsulation: internal packages thực sự hidden

// Tại sao quan trọng cho senior:
// 1. Library design: chỉ export API, hide implementation
// 2. Dependency management: explicit requires
// 3. Security: reflection bị restrict (trừ khi opens)
// 4. Performance: JVM có thể optimize dựa trên module boundaries","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Inheritance — Kế Thừa"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Inheritance là cơ chế tái sử dụng code mạnh mẽ nhưng dễ bị lạm dụng. Senior cần hiểu vtable dispatch, fragile base class problem, Liskov Substitution Principle, và khi nào dùng composition thay vì inheritance."},{"type":"heading","level":2,"text":"Keyword: Virtual Method Dispatch (vtable)"},{"type":"paragraph","text":"**Định nghĩa:** JVM dùng virtual method table để resolve method call tại runtime — nền tảng của polymorphism."},{"type":"code_block","code":"// Mỗi class có một vtable (virtual method table) trong Metaspace
// vtable = array of method pointers, indexed by method slot

// Ví dụ:
class Animal {
    void eat() { }    // vtable slot 0
    void sleep() { }  // vtable slot 1
}

class Dog extends Animal {
    @Override
    void eat() { }    // Override → vtable slot 0 trỏ đến Dog.eat
    void bark() { }   // New method → vtable slot 2
    // sleep() kế thừa → vtable slot 1 vẫn trỏ đến Animal.sleep
}

// Dog vtable:
// [0] → Dog.eat (overridden)
// [1] → Animal.sleep (inherited)
// [2] → Dog.bark (new)

// invokevirtual bytecode:
Animal a = new Dog();
a.eat();
// 1. Load object reference
// 2. Get vtable from object's class pointer
// 3. Lookup method at slot 0
// 4. Call Dog.eat()

// JIT optimization — devirtualization:
// Nếu JIT detect chỉ có 1 implementation → inline trực tiếp
// Monomorphic call site: 1 type → direct call (fastest)
// Bimorphic: 2 types → conditional + direct calls
// Megamorphic: 3+ types → vtable lookup (slowest)

// → final methods và final classes giúp JIT optimize tốt hơn
// → private methods dùng invokespecial (không virtual dispatch)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Fragile Base Class Problem"},{"type":"paragraph","text":"**Định nghĩa:** Thay đổi base class có thể break subclasses theo cách không lường trước — lý do chính để ưu tiên composition."},{"type":"code_block","code":"// Ví dụ kinh điển từ Effective Java:
public class InstrumentedHashSet<E> extends HashSet<E> {
    private int addCount = 0;

    @Override
    public boolean add(E e) {
        addCount++;
        return super.add(e);
    }

    @Override
    public boolean addAll(Collection<? extends E> c) {
        addCount += c.size();
        return super.addAll(c);  // ⚠️ HashSet.addAll() gọi add() cho mỗi element!
    }

    public int getAddCount() { return addCount; }
}

InstrumentedHashSet<String> s = new InstrumentedHashSet<>();
s.addAll(List.of("a", "b", "c"));
s.getAddCount();  // 6! (không phải 3)
// addAll: addCount += 3 (= 3)
// super.addAll() gọi this.add() 3 lần: addCount += 3 (= 6)

// Vấn đề: subclass phụ thuộc vào implementation detail của base class
// Nếu HashSet thay đổi addAll() implementation → subclass break

// ✅ Fix: Composition (Decorator pattern)
public class InstrumentedSet<E> implements Set<E> {
    private final Set<E> delegate;  // Composition
    private int addCount = 0;

    public InstrumentedSet(Set<E> delegate) {
        this.delegate = delegate;
    }

    @Override
    public boolean add(E e) {
        addCount++;
        return delegate.add(e);  // Delegate, không super
    }

    @Override
    public boolean addAll(Collection<? extends E> c) {
        addCount += c.size();
        return delegate.addAll(c);  // Delegate — không bị double-count
    }

    // Delegate tất cả methods khác...
    @Override public int size() { return delegate.size(); }
    @Override public boolean contains(Object o) { return delegate.contains(o); }
    // ...
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Composition over Inheritance"},{"type":"paragraph","text":"**Định nghĩa:** Ưu tiên "has-a" (composition) hơn "is-a" (inheritance) — linh hoạt hơn, ít coupling hơn."},{"type":"code_block","code":"// Khi nào dùng Inheritance:
// 1. Thực sự là quan hệ "is-a" (Dog IS-A Animal)
// 2. Base class được thiết kế cho inheritance (documented, tested)
// 3. Không vi phạm LSP (Liskov Substitution Principle)

// Khi nào dùng Composition:
// 1. "has-a" hoặc "uses-a" relationship
// 2. Cần thay đổi behavior tại runtime
// 3. Cần combine behaviors từ nhiều sources
// 4. Base class không được thiết kế cho inheritance

// Strategy Pattern — composition cho swappable behavior
public class PaymentProcessor {
    private final PaymentStrategy strategy;  // Composition

    public PaymentProcessor(PaymentStrategy strategy) {
        this.strategy = strategy;
    }

    public void process(Order order) {
        strategy.pay(order.getTotal());
    }
}

// Có thể thay đổi strategy tại runtime
PaymentProcessor processor = new PaymentProcessor(new CreditCardPayment());
// Sau đó: new PaymentProcessor(new PayPalPayment())

// Decorator Pattern — composition cho layered behavior
public interface Logger {
    void log(String message);
}

public class ConsoleLogger implements Logger {
    public void log(String message) { System.out.println(message); }
}

public class TimestampLogger implements Logger {
    private final Logger delegate;  // Wrap another logger
    public TimestampLogger(Logger delegate) { this.delegate = delegate; }
    public void log(String message) {
        delegate.log("[" + Instant.now() + "] " + message);
    }
}

public class AsyncLogger implements Logger {
    private final Logger delegate;
    private final ExecutorService executor;
    public void log(String message) {
        executor.submit(() -> delegate.log(message));
    }
}

// Combine behaviors — không thể làm với inheritance
Logger logger = new AsyncLogger(new TimestampLogger(new ConsoleLogger()));

// Mixin via interfaces with default methods (Java 8+)
public interface Auditable {
    default void audit(String action) {
        AuditLog.record(this.getClass().getSimpleName(), action);
    }
}

public interface Cacheable {
    default String cacheKey() {
        return this.getClass().getSimpleName() + ":" + this.hashCode();
    }
}

// Class "mixin" multiple behaviors
public class UserService implements Auditable, Cacheable {
    // Có cả audit() và cacheKey() mà không cần inheritance
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Designing for Inheritance"},{"type":"paragraph","text":"**Định nghĩa:** Nếu class được thiết kế để extend, phải document rõ ràng và test kỹ."},{"type":"code_block","code":"// Effective Java Item 19: Design and document for inheritance or else prohibit it

// Rules cho class designed for inheritance:
// 1. Document self-use patterns
/**
 * {@inheritDoc}
 * <p>Implementation note: this method calls {@link #validate()} before saving.
 * Subclasses overriding validate() will affect save() behavior.</p>
 */
public void save(Entity entity) {
    validate(entity);  // Documented self-use
    doSave(entity);
}

// 2. Provide hooks (protected methods) thay vì force override
protected void beforeSave(Entity entity) { }  // Hook — subclass có thể override
protected void afterSave(Entity entity) { }

// 3. Template Method Pattern
public abstract class AbstractRepository<T> {
    // Template method — defines algorithm skeleton
    public final T save(T entity) {  // final — subclass không thể thay đổi flow
        validate(entity);
        beforeSave(entity);
        T saved = doSave(entity);  // Abstract — subclass implement
        afterSave(saved);
        return saved;
    }

    protected abstract T doSave(T entity);  // Subclass must implement
    protected void validate(T entity) { }   // Optional hook
    protected void beforeSave(T entity) { } // Optional hook
    protected void afterSave(T entity) { }  // Optional hook
}

// 4. Nếu KHÔNG thiết kế cho inheritance → đánh dấu final
public final class String { }      // Cannot extend
public final class Integer { }     // Cannot extend
// Hoặc: package-private constructor → chỉ extend trong cùng package","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Polymorphism — Đa Hình"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Polymorphism là nguyên tắc OOP mạnh nhất — cho phép viết code generic hoạt động với nhiều types. Senior cần hiểu dispatch mechanisms, type erasure implications, và cách leverage polymorphism để thiết kế extensible systems."},{"type":"heading","level":2,"text":"Keyword: Runtime Polymorphism (Dynamic Dispatch)"},{"type":"paragraph","text":"**Định nghĩa:** JVM chọn method implementation tại runtime dựa trên actual type của object."},{"type":"code_block","code":"// Polymorphism cho phép Open/Closed Principle
public interface Notification {
    void send(String message, String recipient);
}

public class EmailNotification implements Notification {
    public void send(String message, String recipient) {
        // Send email
    }
}

public class SmsNotification implements Notification {
    public void send(String message, String recipient) {
        // Send SMS
    }
}

public class PushNotification implements Notification {
    public void send(String message, String recipient) {
        // Send push notification
    }
}

// NotificationService KHÔNG cần biết implementation cụ thể
// Thêm loại mới → thêm class, KHÔNG sửa service
public class NotificationService {
    private final List<Notification> channels;

    public void notifyAll(String message, String recipient) {
        for (Notification channel : channels) {
            channel.send(message, recipient);  // Dynamic dispatch
        }
    }
}

// Double Dispatch — khi cần dispatch dựa trên 2 types
// Java chỉ có single dispatch (dựa trên receiver type)
// Visitor Pattern giải quyết double dispatch:
public interface ShapeVisitor {
    double visit(Circle circle);
    double visit(Rectangle rectangle);
    double visit(Triangle triangle);
}

public interface Shape {
    double accept(ShapeVisitor visitor);  // First dispatch: Shape type
}

public class Circle implements Shape {
    private final double radius;
    public double accept(ShapeVisitor visitor) {
        return visitor.visit(this);  // Second dispatch: visitor.visit(Circle)
    }
}

public class AreaCalculator implements ShapeVisitor {
    public double visit(Circle c) { return Math.PI * c.getRadius() * c.getRadius(); }
    public double visit(Rectangle r) { return r.getWidth() * r.getHeight(); }
    public double visit(Triangle t) { return 0.5 * t.getBase() * t.getHeight(); }
}

// Java 21+ — Pattern matching thay thế Visitor trong nhiều trường hợp
double area(Shape shape) {
    return switch (shape) {
        case Circle c -> Math.PI * c.getRadius() * c.getRadius();
        case Rectangle r -> r.getWidth() * r.getHeight();
        case Triangle t -> 0.5 * t.getBase() * t.getHeight();
    };
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Covariant Return Types"},{"type":"paragraph","text":"**Định nghĩa:** Override method có thể return subtype của original return type — hữu ích cho fluent APIs."},{"type":"code_block","code":"public class Animal {
    public Animal create() {
        return new Animal();
    }
}

public class Dog extends Animal {
    @Override
    public Dog create() {  // Covariant return: Dog thay vì Animal
        return new Dog();
    }
}

// Ứng dụng: Builder pattern với inheritance
public abstract class AbstractBuilder<T extends AbstractBuilder<T>> {
    protected String name;

    @SuppressWarnings("unchecked")
    protected T self() { return (T) this; }

    public T name(String name) {
        this.name = name;
        return self();  // Return concrete builder type
    }
}

public class UserBuilder extends AbstractBuilder<UserBuilder> {
    private String email;

    public UserBuilder email(String email) {
        this.email = email;
        return this;
    }

    public User build() { return new User(name, email); }
}

// Fluent chain không bị "lose type"
User user = new UserBuilder()
    .name("An")      // Returns UserBuilder (not AbstractBuilder)
    .email("an@x.com")  // Available because type preserved
    .build();","language":"java"},{"type":"heading","level":2,"text":"Keyword: Type Erasure & Polymorphism"},{"type":"paragraph","text":"**Định nghĩa:** Generics bị erase tại runtime — ảnh hưởng đến polymorphism với generic types."},{"type":"code_block","code":"// Type erasure: List<String> và List<Integer> cùng là List tại runtime
List<String> strings = new ArrayList<>();
List<Integer> ints = new ArrayList<>();
strings.getClass() == ints.getClass();  // true! Cả hai là ArrayList

// Không thể overload dựa trên generic type
// ❌ Compile error: same erasure
// public void process(List<String> strings) { }
// public void process(List<Integer> ints) { }

// Bridge methods — compiler tạo để maintain polymorphism sau erasure
public interface Comparable<T> {
    int compareTo(T other);
}

public class MyString implements Comparable<MyString> {
    @Override
    public int compareTo(MyString other) { return 0; }
    // Compiler tạo bridge method:
    // public int compareTo(Object other) { return compareTo((MyString) other); }
}

// Reifiable vs Non-reifiable types
// Reifiable: type info available at runtime (primitives, raw types, unbounded wildcards)
// Non-reifiable: type info erased (List<String>, T, ? extends Number)

// instanceof với generics
// ❌ if (obj instanceof List<String>) { }  // Compile error
// ✅ if (obj instanceof List<?>) { }       // OK — unbounded wildcard
// ✅ if (obj instanceof List<?> list && !list.isEmpty()
//        && list.get(0) instanceof String) { }  // Runtime check elements

// Super Type Token pattern — preserve generic type info
// Dùng trong: Jackson TypeReference, Spring ParameterizedTypeReference
abstract class TypeReference<T> {
    private final Type type;
    protected TypeReference() {
        Type superclass = getClass().getGenericSuperclass();
        this.type = ((ParameterizedType) superclass).getActualTypeArguments()[0];
    }
    public Type getType() { return type; }
}

// Usage: anonymous subclass captures type argument
TypeReference<List<String>> ref = new TypeReference<>() {};
ref.getType();  // java.util.List<java.lang.String> — preserved!","language":"java"},{"type":"heading","level":2,"text":"Keyword: Ad-hoc Polymorphism (Method Overloading)"},{"type":"paragraph","text":"**Định nghĩa:** Compile-time polymorphism — compiler chọn method dựa trên static type, KHÔNG phải runtime type."},{"type":"code_block","code":"public class Dispatcher {
    public String dispatch(Object obj) { return "Object"; }
    public String dispatch(String str) { return "String"; }
    public String dispatch(Integer num) { return "Integer"; }
}

Dispatcher d = new Dispatcher();
Object obj = "hello";
d.dispatch(obj);      // "Object"! Không phải "String"
// Vì overloading resolved tại COMPILE TIME dựa trên declared type (Object)

// Nếu cần runtime dispatch dựa trên argument type:
// Pattern 1: instanceof chain (simple but not extensible)
public String dispatch(Object obj) {
    if (obj instanceof String s) return "String: " + s;
    if (obj instanceof Integer i) return "Integer: " + i;
    return "Object: " + obj;
}

// Pattern 2: Visitor pattern (extensible)
// Pattern 3: Map<Class, Handler> (flexible)
private final Map<Class<?>, Function<Object, String>> handlers = Map.of(
    String.class, obj -> "String: " + obj,
    Integer.class, obj -> "Integer: " + obj
);

public String dispatch(Object obj) {
    return handlers.getOrDefault(obj.getClass(), o -> "Unknown: " + o).apply(obj);
}

// Pattern 4: Pattern matching switch (Java 21+)
public String dispatch(Object obj) {
    return switch (obj) {
        case String s -> "String: " + s;
        case Integer i -> "Integer: " + i;
        default -> "Object: " + obj;
    };
}","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Abstraction, Interfaces & Abstract Classes"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Abstraction là nền tảng thiết kế hệ thống — ẩn complexity, expose contract. Senior cần hiểu interface evolution (default methods, sealed interfaces), diamond problem, và khi nào dùng abstract class vs interface."},{"type":"heading","level":2,"text":"Keyword: Interface Evolution (Java 8 → 21)"},{"type":"paragraph","text":"**Định nghĩa:** Interface trong Java đã tiến hóa từ pure contract thành powerful abstraction mechanism."},{"type":"code_block","code":"// Java 1-7: Chỉ abstract methods + constants
public interface Drawable {
    void draw();  // implicitly public abstract
    int MAX_SIZE = 100;  // implicitly public static final
}

// Java 8: default methods + static methods
public interface Collection<E> {
    // Abstract
    boolean add(E e);
    int size();

    // Default — có implementation, subclass có thể override
    default boolean isEmpty() { return size() == 0; }

    default void forEach(Consumer<? super E> action) {
        for (E e : this) action.accept(e);
    }

    // Static — utility methods
    static <E> Collection<E> empty() { return Collections.emptyList(); }
}

// Java 9: private methods (helper cho default methods)
public interface Logger {
    void log(String message);

    default void logInfo(String msg) { log(format("INFO", msg)); }
    default void logError(String msg) { log(format("ERROR", msg)); }

    // Private helper — không visible cho implementors
    private String format(String level, String msg) {
        return "[" + level + "] " + LocalDateTime.now() + " " + msg;
    }
}

// Java 17: sealed interfaces
public sealed interface Shape permits Circle, Rectangle, Triangle {}
// Chỉ 3 classes được implement → compiler biết tất cả subtypes
// → Exhaustive switch không cần default

// Java 21: sealed + pattern matching = algebraic data types
double area(Shape shape) {
    return switch (shape) {
        case Circle c -> Math.PI * c.radius() * c.radius();
        case Rectangle r -> r.width() * r.height();
        case Triangle t -> 0.5 * t.base() * t.height();
        // No default needed — exhaustive
    };
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Diamond Problem & Default Method Conflicts"},{"type":"paragraph","text":"**Định nghĩa:** Khi class implement 2 interfaces có cùng default method — Java có rules rõ ràng để resolve."},{"type":"code_block","code":"public interface A {
    default String hello() { return "A"; }
}

public interface B {
    default String hello() { return "B"; }
}

// ❌ Compile error: class inherits unrelated defaults
// public class C implements A, B { }

// ✅ Must override to resolve conflict
public class C implements A, B {
    @Override
    public String hello() {
        return A.super.hello();  // Explicitly choose A's implementation
        // Hoặc: return B.super.hello();
        // Hoặc: return "C's own implementation";
    }
}

// Resolution rules (JLS §9.4.1.3):
// 1. Class method wins over interface default
// 2. More specific interface wins (sub-interface > super-interface)
// 3. If ambiguous → must override

public interface Base {
    default String name() { return "Base"; }
}

public interface Sub extends Base {
    @Override
    default String name() { return "Sub"; }
}

public class MyClass implements Base, Sub {
    // Sub.name() wins — more specific (Sub extends Base)
    // myClass.name() → "Sub"
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Abstract Class vs Interface — Decision Guide"},{"type":"paragraph","text":"**Định nghĩa:** Khi nào dùng cái nào — không chỉ về syntax mà về design intent."},{"type":"code_block","code":"// Interface: DEFINES A CONTRACT (what to do)
// - "Can do" relationship: Comparable, Serializable, Runnable
// - Multiple inheritance of type
// - Evolve with default methods
// - Clients depend on interface, not implementation

// Abstract Class: SHARES IMPLEMENTATION (how to do)
// - "Is a" relationship with shared state
// - Template Method pattern
// - Constructor logic
// - Non-public members

// Real-world example: Spring Framework
// Interface: Repository<T, ID> — contract
// Abstract class: AbstractRepository — shared implementation
// Concrete: JpaRepository, MongoRepository — specific implementation

// Skeleton Implementation pattern (Effective Java)
// Interface + Abstract class = best of both worlds
public interface Vending<T> {
    void addItem(T item, int quantity);
    T dispense();
    int getStock();
}

// Abstract skeleton — implements common logic
public abstract class AbstractVending<T> implements Vending<T> {
    protected final Map<T, Integer> inventory = new LinkedHashMap<>();

    @Override
    public void addItem(T item, int quantity) {
        inventory.merge(item, quantity, Integer::sum);
    }

    @Override
    public int getStock() {
        return inventory.values().stream().mapToInt(Integer::intValue).sum();
    }

    // dispense() left abstract — subclass decides strategy
}

// Concrete implementations
public class FifoVending<T> extends AbstractVending<T> {
    @Override
    public T dispense() {
        var entry = inventory.entrySet().iterator().next();
        // FIFO logic...
    }
}

// Client code depends on interface Vending<T>
// Implementation can extend AbstractVending or implement Vending directly","language":"java"},{"type":"heading","level":2,"text":"Keyword: Functional Interface & Lambda"},{"type":"paragraph","text":"**Định nghĩa:** Interface với đúng 1 abstract method — nền tảng của functional programming trong Java."},{"type":"code_block","code":"// Built-in functional interfaces (java.util.function)
// Memorize these — dùng hàng ngày:

// Function<T, R>: T → R
Function<String, Integer> length = String::length;
Function<String, String> upper = String::toUpperCase;
Function<String, Integer> composed = upper.andThen(length);  // Compose

// Predicate<T>: T → boolean
Predicate<String> notEmpty = s -> !s.isEmpty();
Predicate<String> isEmail = s -> s.contains("@");
Predicate<String> validEmail = notEmpty.and(isEmail);  // Combine

// Consumer<T>: T → void
Consumer<String> print = System.out::println;
Consumer<String> log = s -> logger.info(s);
Consumer<String> both = print.andThen(log);  // Chain

// Supplier<T>: () → T
Supplier<LocalDateTime> now = LocalDateTime::now;
Supplier<UUID> uuid = UUID::randomUUID;

// UnaryOperator<T>: T → T (special Function)
UnaryOperator<String> trim = String::trim;

// BinaryOperator<T>: (T, T) → T (special BiFunction)
BinaryOperator<Integer> max = Integer::max;

// Primitive specializations — avoid autoboxing
IntFunction<String> intToString = Integer::toString;
ToIntFunction<String> parseInt = Integer::parseInt;
IntPredicate isPositive = i -> i > 0;
IntUnaryOperator doubleIt = i -> i * 2;

// Custom functional interface
@FunctionalInterface
public interface Validator<T> {
    ValidationResult validate(T target);

    default Validator<T> and(Validator<T> other) {
        return target -> {
            ValidationResult result = this.validate(target);
            return result.isValid() ? other.validate(target) : result;
        };
    }
}

// Compose validators
Validator<User> nameValidator = user ->
    user.getName().isBlank() ? ValidationResult.error("Name required") : ValidationResult.ok();
Validator<User> emailValidator = user ->
    !user.getEmail().contains("@") ? ValidationResult.error("Invalid email") : ValidationResult.ok();

Validator<User> fullValidator = nameValidator.and(emailValidator);","language":"java"},{"type":"heading","level":2,"text":"Keyword: Sealed Types (Java 17+)"},{"type":"paragraph","text":"**Định nghĩa:** Restrict hierarchy — chỉ cho phép listed subtypes, enabling exhaustive pattern matching."},{"type":"code_block","code":"// Sealed interface — algebraic data type
public sealed interface Result<T> permits Success, Failure, Loading {
    // Compiler knows ALL possible subtypes
}

public record Success<T>(T data) implements Result<T> {}
public record Failure<T>(String error, Exception cause) implements Result<T> {}
public record Loading<T>(int progress) implements Result<T> {}

// Exhaustive handling — compiler ensures all cases covered
public <T> String describe(Result<T> result) {
    return switch (result) {
        case Success<T> s -> "Data: " + s.data();
        case Failure<T> f -> "Error: " + f.error();
        case Loading<T> l -> "Loading: " + l.progress() + "%";
        // No default needed!
    };
}

// Sealed class hierarchy
public sealed abstract class Expression
    permits Literal, Add, Multiply, Negate {
}

public record Literal(double value) extends Expression {}
public record Add(Expression left, Expression right) extends Expression {}
public record Multiply(Expression left, Expression right) extends Expression {}
public record Negate(Expression operand) extends Expression {}

// Recursive evaluation with pattern matching
public double evaluate(Expression expr) {
    return switch (expr) {
        case Literal l -> l.value();
        case Add a -> evaluate(a.left()) + evaluate(a.right());
        case Multiply m -> evaluate(m.left()) * evaluate(m.right());
        case Negate n -> -evaluate(n.operand());
    };
}

// permits rules:
// - Permitted subtypes must be in same module (or same package if no module)
// - Each subtype must be: final, sealed, or non-sealed
//   final: no further extension
//   sealed: controlled further extension
//   non-sealed: open for extension (escape hatch)","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Enums — Kiểu Liệt Kê"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Enum trong Java là full-featured class — có fields, methods, constructors, implement interfaces. Senior cần hiểu enum internals, EnumSet/EnumMap performance, và advanced patterns như state machine."},{"type":"heading","level":2,"text":"Keyword: Enum Internals"},{"type":"paragraph","text":"**Định nghĩa:** Enum constants là static final instances — JVM đảm bảo singleton, serialization-safe, reflection-safe."},{"type":"code_block","code":"// Compiler transforms enum thành:
public enum Color { RED, GREEN, BLUE }

// Equivalent to:
public final class Color extends Enum<Color> {
    public static final Color RED = new Color("RED", 0);
    public static final Color GREEN = new Color("GREEN", 1);
    public static final Color BLUE = new Color("BLUE", 2);

    private static final Color[] VALUES = {RED, GREEN, BLUE};

    private Color(String name, int ordinal) { super(name, ordinal); }

    public static Color[] values() { return VALUES.clone(); }
    public static Color valueOf(String name) { return Enum.valueOf(Color.class, name); }
}

// Singleton guarantee:
// - Constructor private (compiler enforces)
// - Cannot new enum instances
// - Serialization returns same instance (readResolve)
// - Reflection blocked (Constructor.newInstance throws IllegalArgumentException)

// → Enum là cách tốt nhất implement Singleton (Effective Java Item 3)
public enum DatabaseConfig {
    INSTANCE;
    private final String url = loadFromFile();
    public String getUrl() { return url; }
}

// values() tạo array mới mỗi lần gọi — performance trap trong hot path
// ❌
for (int i = 0; i < 1000000; i++) {
    for (Color c : Color.values()) { }  // 1M array allocations!
}
// ✅ Cache values
private static final Color[] CACHED_VALUES = Color.values();","language":"java"},{"type":"heading","level":2,"text":"Keyword: EnumSet & EnumMap"},{"type":"paragraph","text":"**Định nghĩa:** Specialized collections cho enums — dùng bitmask internally, cực kỳ nhanh."},{"type":"code_block","code":"// EnumSet — Set<E extends Enum<E>> backed by bit vector
// O(1) cho add, remove, contains — nhanh hơn HashSet
EnumSet<Permission> perms = EnumSet.of(Permission.READ, Permission.WRITE);
perms.add(Permission.EXECUTE);
perms.contains(Permission.READ);  // O(1) — single bit check
perms.containsAll(EnumSet.of(Permission.READ, Permission.WRITE));  // O(1) — bitwise AND

// Internal: long bitmask (≤64 enum constants) hoặc long[] (>64)
// Permission.READ  = bit 0 = 0b001
// Permission.WRITE = bit 1 = 0b010
// Permission.EXEC  = bit 2 = 0b100
// {READ, WRITE} = 0b011

// EnumMap — Map<K extends Enum<K>, V> backed by array
// O(1) cho get, put — nhanh hơn HashMap, no hashing
EnumMap<DayOfWeek, String> schedule = new EnumMap<>(DayOfWeek.class);
schedule.put(DayOfWeek.MONDAY, "Meeting");
schedule.put(DayOfWeek.FRIDAY, "Review");

// Internal: Object[] indexed by ordinal
// schedule.get(MONDAY) → array[MONDAY.ordinal()] → O(1)

// → LUÔN dùng EnumSet/EnumMap thay vì HashSet/HashMap cho enum keys","language":"java"},{"type":"heading","level":2,"text":"Keyword: Enum Advanced Patterns"},{"type":"paragraph","text":"**Định nghĩa:** Enum với abstract methods, interface implementation, và state machine pattern."},{"type":"code_block","code":"// Strategy Pattern với enum
public enum DiscountStrategy {
    NONE {
        public BigDecimal apply(BigDecimal price) { return price; }
    },
    PERCENT_10 {
        public BigDecimal apply(BigDecimal price) {
            return price.multiply(new BigDecimal("0.90"));
        }
    },
    FIXED_50 {
        public BigDecimal apply(BigDecimal price) {
            return price.subtract(new BigDecimal("50")).max(BigDecimal.ZERO);
        }
    };

    public abstract BigDecimal apply(BigDecimal price);
}

// State Machine Pattern
public enum OrderStatus {
    PENDING {
        @Override
        public Set<OrderStatus> allowedTransitions() {
            return EnumSet.of(CONFIRMED, CANCELLED);
        }
    },
    CONFIRMED {
        @Override
        public Set<OrderStatus> allowedTransitions() {
            return EnumSet.of(SHIPPED, CANCELLED);
        }
    },
    SHIPPED {
        @Override
        public Set<OrderStatus> allowedTransitions() {
            return EnumSet.of(DELIVERED);
        }
    },
    DELIVERED {
        @Override
        public Set<OrderStatus> allowedTransitions() {
            return EnumSet.noneOf(OrderStatus.class);  // Terminal state
        }
    },
    CANCELLED {
        @Override
        public Set<OrderStatus> allowedTransitions() {
            return EnumSet.noneOf(OrderStatus.class);  // Terminal state
        }
    };

    public abstract Set<OrderStatus> allowedTransitions();

    public boolean canTransitionTo(OrderStatus target) {
        return allowedTransitions().contains(target);
    }

    public OrderStatus transitionTo(OrderStatus target) {
        if (!canTransitionTo(target)) {
            throw new IllegalStateException(
                "Cannot transition from " + this + " to " + target);
        }
        return target;
    }
}

// Reverse lookup — name/code → enum
public enum HttpStatus {
    OK(200), NOT_FOUND(404), INTERNAL_ERROR(500);

    private final int code;
    HttpStatus(int code) { this.code = code; }

    // ❌ Slow: O(n) linear search
    public static HttpStatus fromCode(int code) {
        for (HttpStatus s : values()) {
            if (s.code == code) return s;
        }
        throw new IllegalArgumentException("Unknown: " + code);
    }

    // ✅ Fast: O(1) lookup with cached map
    private static final Map<Integer, HttpStatus> BY_CODE =
        Arrays.stream(values()).collect(Collectors.toMap(s -> s.code, s -> s));

    public static HttpStatus fromCodeFast(int code) {
        HttpStatus status = BY_CODE.get(code);
        if (status == null) throw new IllegalArgumentException("Unknown: " + code);
        return status;
    }
}","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"SOLID Principles — Nguyên Tắc SOLID"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"SOLID là 5 nguyên tắc thiết kế OOP của Robert C. Martin. Senior cần hiểu không chỉ định nghĩa mà cả trade-offs, khi nào áp dụng, khi nào vi phạm có chủ đích, và cách Spring Framework leverage SOLID."},{"type":"heading","level":2,"text":"Keyword: Single Responsibility Principle (SRP)"},{"type":"paragraph","text":"**Định nghĩa:** Mỗi class chỉ có MỘT lý do để thay đổi — một actor/stakeholder chịu trách nhiệm."},{"type":"code_block","code":"// SRP không phải "mỗi class làm 1 việc" — mà là "1 lý do thay đổi"
// "Lý do thay đổi" = actor/stakeholder yêu cầu thay đổi

// ❌ Vi phạm: Employee class phục vụ 3 actors
public class Employee {
    public BigDecimal calculatePay() { }     // CFO yêu cầu thay đổi
    public int calculateHours() { }          // COO yêu cầu thay đổi
    public void save() { }                   // CTO yêu cầu thay đổi
}
// Thay đổi cho CFO có thể break logic của COO

// ✅ Tách theo actor
public class PayCalculator { public BigDecimal calculate(Employee e) { } }
public class HourTracker { public int calculate(Employee e) { } }
public class EmployeeRepository { public void save(Employee e) { } }

// Spring áp dụng SRP:
// @Controller — chỉ handle HTTP request/response
// @Service — chỉ business logic
// @Repository — chỉ data access
// Mỗi layer thay đổi vì lý do khác nhau

// Trade-off: Quá nhiều classes nhỏ → complexity tăng
// Balance: Tách khi có DỰ KIẾN thay đổi độc lập, không tách preventively","language":"java"},{"type":"heading","level":2,"text":"Keyword: Open/Closed Principle (OCP)"},{"type":"paragraph","text":"**Định nghĩa:** Mở cho extension, đóng cho modification — thêm behavior mới mà không sửa code cũ."},{"type":"code_block","code":"// OCP thường đạt được qua: Strategy, Template Method, Observer, Plugin architecture

// Ví dụ thực tế: Notification system
// ❌ Mỗi lần thêm channel → sửa method
public void notify(String type, String message) {
    if ("email".equals(type)) sendEmail(message);
    else if ("sms".equals(type)) sendSms(message);
    else if ("push".equals(type)) sendPush(message);
    // Thêm "slack" → sửa method này
}

// ✅ OCP: thêm channel = thêm class
public interface NotificationChannel {
    boolean supports(String type);
    void send(String message);
}

@Component
public class NotificationService {
    private final List<NotificationChannel> channels;  // Spring inject tất cả implementations

    public void notify(String type, String message) {
        channels.stream()
            .filter(ch -> ch.supports(type))
            .forEach(ch -> ch.send(message));
    }
}

// Thêm Slack: tạo SlackChannel implements NotificationChannel
// NotificationService KHÔNG cần sửa

// Spring Boot auto-configuration là OCP ở cấp framework:
// Thêm dependency → auto-configure → không sửa code
// spring-boot-starter-data-jpa → tự cấu hình JPA
// spring-boot-starter-security → tự cấu hình Security","language":"java"},{"type":"heading","level":2,"text":"Keyword: Liskov Substitution Principle (LSP)"},{"type":"paragraph","text":"**Định nghĩa:** Subtype phải thay thế được supertype mà không làm sai program behavior — behavioral subtyping."},{"type":"code_block","code":"// LSP formal rules:
// 1. Preconditions cannot be strengthened in subtype
// 2. Postconditions cannot be weakened in subtype
// 3. Invariants of supertype must be preserved
// 4. History constraint: subtype cannot add state changes supertype doesn't allow

// ❌ Classic violation: Square extends Rectangle
public class Rectangle {
    protected int width, height;
    public void setWidth(int w) { this.width = w; }
    public void setHeight(int h) { this.height = h; }
    public int area() { return width * height; }
}

public class Square extends Rectangle {
    @Override
    public void setWidth(int w) { this.width = w; this.height = w; }
    @Override
    public void setHeight(int h) { this.width = h; this.height = h; }
}

// Client code expects Rectangle behavior:
void resize(Rectangle r) {
    r.setWidth(5);
    r.setHeight(3);
    assert r.area() == 15;  // FAILS for Square! area = 9
}
// Square strengthens postcondition of setWidth (also changes height)
// → Violates LSP

// ✅ Fix: separate types, no inheritance
public interface Shape { double area(); }
public record Rectangle(double width, double height) implements Shape {
    public double area() { return width * height; }
}
public record Square(double side) implements Shape {
    public double area() { return side * side; }
}

// Real-world LSP violations to watch for:
// 1. Throwing UnsupportedOperationException
//    Collections.unmodifiableList() returns List that throws on add()
//    → Technically violates LSP (weakens postcondition)
//    → Accepted trade-off in Java Collections

// 2. Subclass restricting valid inputs
//    Base: accepts any positive number
//    Sub: only accepts even numbers → strengthens precondition → LSP violation

// 3. Subclass changing observable behavior
//    Base: sort() is stable
//    Sub: sort() is unstable → weakens postcondition → LSP violation","language":"java"},{"type":"heading","level":2,"text":"Keyword: Interface Segregation Principle (ISP)"},{"type":"paragraph","text":"**Định nghĩa:** Clients không nên phụ thuộc vào methods không dùng — chia interface lớn thành nhỏ, focused."},{"type":"code_block","code":"// ISP trong Spring:
// CrudRepository<T, ID> — basic CRUD
// PagingAndSortingRepository<T, ID> extends CrudRepository — + paging
// JpaRepository<T, ID> extends PagingAndSortingRepository — + JPA specific

// Client chỉ cần CRUD → depend on CrudRepository
// Client cần paging → depend on PagingAndSortingRepository
// Không bị force depend on JPA-specific methods

// ISP cho service interfaces:
// ❌ Fat interface
public interface UserService {
    User findById(Long id);
    List<User> findAll();
    User create(CreateUserRequest req);
    User update(Long id, UpdateUserRequest req);
    void delete(Long id);
    void sendVerificationEmail(Long userId);
    void resetPassword(Long userId);
    Report generateUserReport();
    void importFromCsv(InputStream csv);
    void exportToCsv(OutputStream csv);
}

// ✅ Segregated interfaces
public interface UserReader {
    User findById(Long id);
    List<User> findAll();
}

public interface UserWriter {
    User create(CreateUserRequest req);
    User update(Long id, UpdateUserRequest req);
    void delete(Long id);
}

public interface UserNotification {
    void sendVerificationEmail(Long userId);
    void resetPassword(Long userId);
}

// CQRS pattern tự nhiên từ ISP:
// Read operations: UserReader
// Write operations: UserWriter
// Có thể scale independently","language":"java"},{"type":"heading","level":2,"text":"Keyword: Dependency Inversion Principle (DIP)"},{"type":"paragraph","text":"**Định nghĩa:** High-level modules không phụ thuộc low-level modules — cả hai phụ thuộc abstractions. Đây là nền tảng của Spring DI."},{"type":"code_block","code":"// DIP = Inversion of Control (IoC) ở design level
// Spring DI = implementation của DIP

// ❌ High-level depends on low-level
public class OrderService {
    private final MySQLOrderRepository repo = new MySQLOrderRepository();
    // OrderService phụ thuộc trực tiếp vào MySQL implementation
    // Đổi sang PostgreSQL → sửa OrderService
}

// ✅ Both depend on abstraction
public interface OrderRepository {  // Abstraction
    void save(Order order);
    Optional<Order> findById(Long id);
}

@Repository
public class JpaOrderRepository implements OrderRepository {  // Low-level
    // JPA implementation
}

@Service
public class OrderService {  // High-level
    private final OrderRepository repository;  // Depends on abstraction

    public OrderService(OrderRepository repository) {
        this.repository = repository;  // Spring injects implementation
    }
}

// DIP enables:
// 1. Testability — inject mock repository
@Test
void testCreateOrder() {
    OrderRepository mockRepo = mock(OrderRepository.class);
    OrderService service = new OrderService(mockRepo);
    // Test business logic without database
}

// 2. Flexibility — swap implementations
// Dev: H2 in-memory
// Prod: PostgreSQL
// Test: Mock
// Tất cả implement cùng OrderRepository interface

// 3. Plugin architecture
// Core module defines interfaces
// Plugin modules provide implementations
// Core không biết plugins tồn tại → loose coupling

// Dependency Rule (Clean Architecture):
// Source code dependencies point INWARD
// Outer layers depend on inner layers
// Inner layers NEVER depend on outer layers
//
// Domain (entities) → knows nothing
// Use Cases → depends on Domain
// Interface Adapters → depends on Use Cases
// Frameworks → depends on Interface Adapters","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Generics — Kiểu Tổng Quát"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Generics cung cấp compile-time type safety cho collections và APIs. Senior cần hiểu type erasure implications, PECS principle, recursive type bounds, và type token patterns."},{"type":"heading","level":2,"text":"Keyword: Type Erasure — Deep Dive"},{"type":"paragraph","text":"**Định nghĩa:** Compiler xóa generic type info, thay bằng bounds (hoặc Object) — generics chỉ tồn tại tại compile time."},{"type":"code_block","code":"// Compiler transforms:
List<String> list = new ArrayList<>();
list.add("hello");
String s = list.get(0);

// Thành (sau erasure):
List list = new ArrayList();
list.add("hello");
String s = (String) list.get(0);  // Compiler insert cast

// Erasure rules:
// T → Object (unbounded)
// T extends Comparable → Comparable (bounded)
// T extends Comparable & Serializable → Comparable (first bound)

// Consequences:
// 1. Cannot use instanceof with generic type
// if (obj instanceof List<String>) { }  // ERROR
if (obj instanceof List<?>) { }          // OK

// 2. Cannot create generic array
// T[] arr = new T[10];  // ERROR
// List<String>[] arr = new List<String>[10];  // ERROR
@SuppressWarnings("unchecked")
T[] arr = (T[]) new Object[10];  // Workaround (unsafe)

// 3. Cannot use primitives
// List<int> nums;  // ERROR — must use List<Integer>

// 4. Static fields cannot use class type parameter
public class Box<T> {
    // static T value;  // ERROR — T is per-instance, static is per-class
    static Object value;  // OK
}

// 5. Cannot overload by generic type
// void process(List<String> s) { }
// void process(List<Integer> i) { }  // ERROR: same erasure

// Bridge methods — maintain polymorphism after erasure
public interface Comparable<T> {
    int compareTo(T o);
}
public class MyInt implements Comparable<MyInt> {
    public int compareTo(MyInt o) { return 0; }
    // Compiler generates bridge:
    // public int compareTo(Object o) { return compareTo((MyInt) o); }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: PECS — Producer Extends, Consumer Super"},{"type":"paragraph","text":"**Định nghĩa:** Wildcard guideline: dùng `? extends T` khi đọc (produce), `? super T` khi ghi (consume)."},{"type":"code_block","code":"// Producer Extends — đọc items từ collection
public double sum(List<? extends Number> numbers) {
    double total = 0;
    for (Number n : numbers) {  // Đọc as Number ✓
        total += n.doubleValue();
    }
    // numbers.add(1);  // ERROR! Cannot add — compiler không biết exact type
    return total;
}
sum(List.of(1, 2, 3));        // List<Integer> ✓
sum(List.of(1.5, 2.5));       // List<Double> ✓

// Consumer Super — ghi items vào collection
public void addNumbers(List<? super Integer> list) {
    list.add(1);     // Ghi Integer ✓
    list.add(2);
    // Integer n = list.get(0);  // ERROR! get() returns Object
    Object obj = list.get(0);    // Chỉ đọc as Object
}
addNumbers(new ArrayList<Integer>());  // ✓
addNumbers(new ArrayList<Number>());   // ✓
addNumbers(new ArrayList<Object>());   // ✓

// Real-world PECS: Collections.copy
public static <T> void copy(List<? super T> dest, List<? extends T> src) {
    // src: producer (đọc) → extends
    // dest: consumer (ghi) → super
    for (int i = 0; i < src.size(); i++) {
        dest.set(i, src.get(i));
    }
}

// Comparable/Comparator luôn dùng super
// ❌
public static <T extends Comparable<T>> T max(List<T> list) { }
// ✅ Flexible hơn — chấp nhận Comparable của supertype
public static <T extends Comparable<? super T>> T max(List<? extends T> list) { }
// Ví dụ: ScheduledFuture extends Delayed extends Comparable<Delayed>
// max(List<ScheduledFuture>) cần Comparable<? super ScheduledFuture>

// Capture helper — khi cần "capture" wildcard type
public void swap(List<?> list, int i, int j) {
    swapHelper(list, i, j);  // Delegate to capture wildcard
}
private <T> void swapHelper(List<T> list, int i, int j) {
    T temp = list.get(i);
    list.set(i, list.get(j));
    list.set(j, temp);
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Recursive Type Bounds"},{"type":"paragraph","text":"**Định nghĩa:** Type parameter tham chiếu đến chính nó — pattern cho self-referential types."},{"type":"code_block","code":"// Pattern: <T extends Comparable<T>>
// "T là kiểu có thể so sánh với chính nó"
public static <T extends Comparable<T>> T max(Collection<T> collection) {
    T result = null;
    for (T element : collection) {
        if (result == null || element.compareTo(result) > 0) {
            result = element;
        }
    }
    return result;
}

// Builder pattern với self-type
public abstract class Builder<T extends Builder<T>> {
    protected String name;

    @SuppressWarnings("unchecked")
    protected T self() { return (T) this; }

    public T name(String name) {
        this.name = name;
        return self();
    }
}

public class UserBuilder extends Builder<UserBuilder> {
    private String email;
    public UserBuilder email(String email) { this.email = email; return this; }
    public User build() { return new User(name, email); }
}

// Chain preserves concrete type:
new UserBuilder().name("An").email("an@x.com").build();
// name() returns UserBuilder (not Builder) → email() available

// Enum self-type: Enum<E extends Enum<E>>
// Mọi enum implicitly: public final class Color extends Enum<Color>
// Cho phép: Comparable<Color>, valueOf(Color.class, "RED")","language":"java"},{"type":"heading","level":2,"text":"Keyword: Type Tokens & Super Type Tokens"},{"type":"paragraph","text":"**Định nghĩa:** Patterns để preserve generic type info tại runtime — vượt qua type erasure."},{"type":"code_block","code":"// Simple type token — Class<T>
public <T> T deserialize(String json, Class<T> type) {
    // type.getName() available at runtime
    return objectMapper.readValue(json, type);
}
String user = deserialize(jsonStr, String.class);

// Problem: Class<T> không capture generic parameters
// deserialize(json, List.class) → List (raw), không phải List<String>

// Super Type Token — capture full generic type
// Pattern từ Neal Gafter, dùng trong Jackson, Spring, Guice
public abstract class TypeReference<T> {
    private final Type type;

    protected TypeReference() {
        Type superclass = getClass().getGenericSuperclass();
        this.type = ((ParameterizedType) superclass).getActualTypeArguments()[0];
    }

    public Type getType() { return type; }
}

// Usage — anonymous subclass captures type argument
TypeReference<List<String>> ref = new TypeReference<>() {};
ref.getType();  // java.util.List<java.lang.String>

// Jackson usage:
List<User> users = objectMapper.readValue(json, new TypeReference<List<User>>() {});

// Spring usage:
ResponseEntity<List<User>> response = restTemplate.exchange(
    url, HttpMethod.GET, null,
    new ParameterizedTypeReference<List<User>>() {}
);

// Tại sao hoạt động?
// Anonymous class: new TypeReference<List<String>>() {}
// Compiler lưu generic superclass info trong bytecode (Signature attribute)
// getGenericSuperclass() đọc info này tại runtime
// → Type parameter KHÔNG bị erase cho class declarations, chỉ erase cho local usage","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Collections Framework — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Collections Framework là backbone của Java applications. Senior cần hiểu internal data structures, time complexity, thread-safety characteristics, và chọn đúng implementation cho từng use case."},{"type":"heading","level":2,"text":"Keyword: HashMap Internals"},{"type":"paragraph","text":"**Định nghĩa:** Hash table implementation — array of buckets, separate chaining, treeification (Java 8+)."},{"type":"code_block","code":"// Internal structure:
// Node<K,V>[] table — array of buckets
// Default initial capacity: 16
// Default load factor: 0.75
// Resize: double capacity khi size > capacity * loadFactor

// Hash computation:
// 1. key.hashCode() → int (32 bits)
// 2. Spread: hash ^ (hash >>> 16) — mix high bits into low bits
// 3. Bucket index: hash & (capacity - 1) — bitwise AND (capacity is power of 2)

// Collision resolution:
// Java 7: Linked list (O(n) worst case)
// Java 8+: Linked list → Red-Black tree khi bucket size >= 8
//          Tree → Linked list khi bucket size <= 6
// → Worst case: O(log n) thay vì O(n)

// Treeification requires: key implements Comparable
// Nếu không Comparable → compare by identityHashCode (less efficient)

// Performance implications:
// Good hashCode: O(1) average for get/put
// Bad hashCode (all same hash): O(log n) with treeification
// Resize: O(n) — rehash all entries

// hashCode() quality matters enormously:
// ❌ Bad: return 1; → all entries in 1 bucket → O(n)
// ❌ Bad: return random; → same key different hash → lost entries
// ✅ Good: Objects.hash(field1, field2) — well-distributed

// ConcurrentHashMap (Java 8+):
// - Lock striping: lock per bucket (not entire map)
// - CAS operations for simple updates
// - No null keys or values (unlike HashMap)
// - size() is approximate in concurrent scenarios
// - computeIfAbsent() is atomic

ConcurrentHashMap<String, AtomicLong> counters = new ConcurrentHashMap<>();
counters.computeIfAbsent("hits", k -> new AtomicLong()).incrementAndGet();
// Thread-safe without external synchronization

// LinkedHashMap — HashMap + doubly-linked list
// Maintains insertion order (or access order for LRU cache)
// LRU Cache implementation:
LinkedHashMap<String, Object> lruCache = new LinkedHashMap<>(16, 0.75f, true) {
    @Override
    protected boolean removeEldestEntry(Map.Entry<String, Object> eldest) {
        return size() > MAX_CACHE_SIZE;
    }
};

// TreeMap — Red-Black tree, sorted by key
// O(log n) for get/put/remove
// NavigableMap: floorKey, ceilingKey, subMap, headMap, tailMap
TreeMap<LocalDate, Event> events = new TreeMap<>();
events.floorEntry(today);     // Latest event on or before today
events.subMap(startDate, endDate);  // Events in range","language":"java"},{"type":"heading","level":2,"text":"Keyword: ArrayList vs LinkedList — Real Performance"},{"type":"paragraph","text":"**Định nghĩa:** ArrayList gần như luôn nhanh hơn LinkedList — ngay cả cho insertions."},{"type":"code_block","code":"// Common misconception: "LinkedList tốt cho insert/delete"
// Reality: ArrayList thường nhanh hơn do CPU cache locality

// ArrayList: contiguous memory → cache-friendly
// LinkedList: scattered nodes → cache misses

// Benchmark results (typical):
// Random access:    ArrayList O(1)  vs LinkedList O(n)     → ArrayList wins
// Iteration:        ArrayList fast  vs LinkedList slow     → ArrayList wins (cache)
// Add at end:       ArrayList O(1)* vs LinkedList O(1)     → Similar
// Add at beginning: ArrayList O(n)  vs LinkedList O(1)     → LinkedList wins
// Add in middle:    ArrayList O(n)  vs LinkedList O(n)**   → ArrayList often wins!

// * ArrayList amortized O(1) — occasional O(n) resize
// ** LinkedList O(n) to FIND position + O(1) to insert
//    But finding position requires traversal → cache misses

// When to actually use LinkedList:
// 1. Frequent add/remove at BOTH ends → use as Deque
// 2. Iterator-based removal during iteration
// 3. Almost never for general-purpose List

// ArrayList capacity management:
ArrayList<String> list = new ArrayList<>(1000);  // Pre-size if known
// Default capacity: 10
// Growth: oldCapacity + (oldCapacity >> 1) = 1.5x
// 10 → 15 → 22 → 33 → 49 → ...
// ensureCapacity(minCapacity) — pre-allocate
// trimToSize() — shrink to actual size

// Immutable lists (Java 9+):
List<String> immutable = List.of("a", "b", "c");
// Internal: specialized classes for 0-2 elements, array-based for 3+
// List.of() with 0 elements → singleton empty list
// List.of(e1) → specialized 1-element class (no array!)
// List.of(e1, e2) → specialized 2-element class
// List.of(e1, e2, e3, ...) → array-based
// → Memory efficient for small lists","language":"java"},{"type":"heading","level":2,"text":"Keyword: Set Implementations"},{"type":"paragraph","text":"**Định nghĩa:** HashSet, LinkedHashSet, TreeSet — chọn dựa trên ordering requirements."},{"type":"code_block","code":"// HashSet: HashMap internally (value = dummy PRESENT object)
// O(1) add/remove/contains
// No ordering guarantee
// Allows null (1 null element)

// LinkedHashSet: LinkedHashMap internally
// O(1) operations + maintains insertion order
// Slightly slower than HashSet (linked list overhead)

// TreeSet: TreeMap internally (Red-Black tree)
// O(log n) operations
// Sorted order (natural or Comparator)
// NavigableSet: floor, ceiling, subSet, headSet, tailSet
// Does NOT allow null (needs comparison)

// CopyOnWriteArraySet: thread-safe, optimized for read-heavy
// Every write creates new array copy → expensive writes
// Iteration never throws ConcurrentModificationException
// Use for: small sets, read-mostly, event listeners

// Choosing the right Set:
// Need fast lookup, no order? → HashSet
// Need insertion order? → LinkedHashSet
// Need sorted order? → TreeSet
// Need thread-safe, read-heavy? → CopyOnWriteArraySet
// Need thread-safe, write-heavy? → ConcurrentHashMap.newKeySet()
// Enum values? → EnumSet (always!)

// Set operations:
Set<String> a = Set.of("1", "2", "3");
Set<String> b = Set.of("2", "3", "4");

// Union: a ∪ b
Set<String> union = new HashSet<>(a);
union.addAll(b);  // {1, 2, 3, 4}

// Intersection: a ∩ b
Set<String> intersection = new HashSet<>(a);
intersection.retainAll(b);  // {2, 3}

// Difference: a \ b
Set<String> difference = new HashSet<>(a);
difference.removeAll(b);  // {1}

// Symmetric difference: a △ b
Set<String> symDiff = new HashSet<>(a);
symDiff.addAll(b);
Set<String> tmp = new HashSet<>(a);
tmp.retainAll(b);
symDiff.removeAll(tmp);  // {1, 4}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Queue & Deque — Choosing Right Implementation"},{"type":"paragraph","text":"**Định nghĩa:** Queue (FIFO), Deque (double-ended), PriorityQueue (heap) — mỗi cái cho use case khác."},{"type":"code_block","code":"// ArrayDeque — preferred general-purpose Deque/Stack
// Resizable circular array — faster than LinkedList for both Stack and Queue
// No null elements
Deque<String> stack = new ArrayDeque<>();  // Use as Stack (LIFO)
stack.push("a"); stack.push("b");
stack.pop();  // "b"

Deque<String> queue = new ArrayDeque<>();  // Use as Queue (FIFO)
queue.offer("a"); queue.offer("b");
queue.poll();  // "a"

// PriorityQueue — binary heap
// O(log n) offer/poll, O(1) peek
// NOT thread-safe
// Natural ordering or custom Comparator
PriorityQueue<Task> taskQueue = new PriorityQueue<>(
    Comparator.comparing(Task::getPriority).reversed()  // High priority first
);

// BlockingQueue — thread-safe, blocking operations
// Producer-Consumer pattern
BlockingQueue<Job> jobQueue = new LinkedBlockingQueue<>(100);  // Bounded
// Producer:
jobQueue.put(job);      // Blocks if full
// Consumer:
Job job = jobQueue.take();  // Blocks if empty

// Implementations:
// ArrayBlockingQueue: bounded, fair option
// LinkedBlockingQueue: optionally bounded
// PriorityBlockingQueue: unbounded, priority-based
// SynchronousQueue: zero-capacity, direct handoff
// DelayQueue: elements available after delay

// SynchronousQueue — special: no internal capacity
// put() blocks until another thread calls take()
// Used in: Executors.newCachedThreadPool()","language":"java"},{"type":"heading","level":2,"text":"Keyword: Fail-Fast vs Fail-Safe Iterators"},{"type":"paragraph","text":"**Định nghĩa:** Fail-fast throw ConcurrentModificationException; fail-safe work on copy/snapshot."},{"type":"code_block","code":"// Fail-fast: ArrayList, HashMap, HashSet, etc.
// Detect structural modification during iteration → throw CME
List<String> list = new ArrayList<>(List.of("a", "b", "c"));
for (String s : list) {
    list.remove(s);  // ConcurrentModificationException!
}

// Internal: modCount field tracks structural modifications
// Iterator checks modCount on each next() call
// If modCount changed → throw CME

// Safe removal during iteration:
// 1. Iterator.remove()
Iterator<String> it = list.iterator();
while (it.hasNext()) {
    if (it.next().equals("b")) it.remove();
}

// 2. removeIf() (Java 8+)
list.removeIf(s -> s.equals("b"));

// 3. Collect + removeAll
list.removeAll(list.stream().filter(s -> s.equals("b")).toList());

// Fail-safe: ConcurrentHashMap, CopyOnWriteArrayList
// Work on snapshot or allow concurrent modification
ConcurrentHashMap<String, Integer> map = new ConcurrentHashMap<>();
for (Map.Entry<String, Integer> entry : map.entrySet()) {
    map.remove(entry.getKey());  // OK! No CME
}
// But: iterator may not reflect all concurrent changes

// CopyOnWriteArrayList: every write creates new array
// Iteration uses snapshot → never CME
// Good for: event listeners, read-heavy small lists
// Bad for: large lists, write-heavy","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Lambda Expressions & Stream API — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Lambda và Stream API là paradigm shift trong Java — từ imperative sang functional style. Senior cần hiểu lambda capture semantics, stream pipeline internals, parallel stream pitfalls, và performance characteristics."},{"type":"heading","level":2,"text":"Keyword: Lambda Internals"},{"type":"paragraph","text":"**Định nghĩa:** Lambda KHÔNG phải anonymous class — JVM dùng invokedynamic + LambdaMetafactory để tạo tại runtime."},{"type":"code_block","code":"// Anonymous class vs Lambda — khác biệt quan trọng:

// Anonymous class:
// - Tạo .class file riêng (Outer$1.class)
// - new object mỗi lần
// - this = anonymous class instance
Runnable anon = new Runnable() {
    public void run() {
        System.out.println(this.getClass());  // Outer$1
    }
};

// Lambda:
// - KHÔNG tạo .class file
// - invokedynamic → LambdaMetafactory tạo class tại runtime
// - Có thể reuse instance (nếu non-capturing)
// - this = enclosing class instance
Runnable lambda = () -> {
    System.out.println(this.getClass());  // Outer (enclosing class!)
};

// Non-capturing lambda — có thể được cache (singleton)
Runnable nonCapturing = () -> System.out.println("hello");
// JVM có thể tạo 1 instance và reuse → no allocation per call

// Capturing lambda — capture variables, tạo instance mới
String name = "An";
Runnable capturing = () -> System.out.println(name);
// Phải tạo instance mới để hold captured value

// Capture rules:
// - Local variables: phải effectively final (copy by value)
// - Instance fields: capture this reference (mutable!)
// - Static fields: access trực tiếp (mutable!)

int counter = 0;
// list.forEach(item -> counter++);  // ERROR: counter not effectively final

// Workaround cho mutable state trong lambda:
AtomicInteger counter = new AtomicInteger(0);
list.forEach(item -> counter.incrementAndGet());  // OK: reference is final

// Hoặc dùng array (hack, không khuyến khích):
int[] count = {0};
list.forEach(item -> count[0]++);  // OK: array ref is final, content mutable","language":"java"},{"type":"heading","level":2,"text":"Keyword: Method Reference Types"},{"type":"paragraph","text":"**Định nghĩa:** 4 loại method reference — mỗi loại có capture behavior khác nhau."},{"type":"code_block","code":"// 1. Static method: ClassName::staticMethod
Function<String, Integer> parse = Integer::parseInt;
// Equivalent: s -> Integer.parseInt(s)
// Non-capturing → có thể cache

// 2. Bound instance method: instance::method
String prefix = "Hello";
Function<String, String> greet = prefix::concat;
// Equivalent: s -> prefix.concat(s)
// Capturing: captures prefix reference

// 3. Unbound instance method: ClassName::instanceMethod
Function<String, Integer> len = String::length;
// Equivalent: s -> s.length()
// First parameter becomes receiver
// Non-capturing → có thể cache

BiFunction<String, String, Boolean> eq = String::equals;
// Equivalent: (s1, s2) -> s1.equals(s2)

// 4. Constructor reference: ClassName::new
Supplier<ArrayList<String>> factory = ArrayList::new;
// Equivalent: () -> new ArrayList<>()

Function<Integer, ArrayList<String>> sizedFactory = ArrayList::new;
// Equivalent: size -> new ArrayList<>(size)
// Compiler chọn constructor dựa trên functional interface signature

// Array constructor reference
IntFunction<String[]> arrayFactory = String[]::new;
// Equivalent: size -> new String[size]
// Dùng trong: stream.toArray(String[]::new)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Stream Pipeline Internals"},{"type":"paragraph","text":"**Định nghĩa:** Stream pipeline = source + intermediate ops (lazy) + terminal op (triggers execution)."},{"type":"code_block","code":"// Stream KHÔNG lưu data — chỉ là pipeline description
// Execution chỉ xảy ra khi terminal operation được gọi

// Lazy evaluation — intermediate ops không chạy cho đến khi terminal op
List<String> names = List.of("An", "Bình", "Cường", "Dũng", "Em");
names.stream()
    .filter(n -> {
        System.out.println("filter: " + n);  // Chỉ in khi terminal op chạy
        return n.length() > 2;
    })
    .map(n -> {
        System.out.println("map: " + n);
        return n.toUpperCase();
    })
    .findFirst();  // Terminal op

// Output:
// filter: An       (length 2, filtered out)
// filter: Bình     (length 4, passes)
// map: Bình        (transform)
// → Stops! findFirst() short-circuits — Cường, Dũng, Em never processed

// Stream pipeline fusion:
// JVM có thể merge multiple operations thành single pass
// filter + map + collect → single loop internally

// Stream characteristics — affect optimization:
// ORDERED: elements have encounter order (List, LinkedHashSet)
// DISTINCT: no duplicates (Set)
// SORTED: elements are sorted (TreeSet, sorted())
// SIZED: known size (Collection, not filter result)
// NONNULL: no null elements (some sources)
// IMMUTABLE: source cannot be modified
// CONCURRENT: source supports concurrent modification

// unordered() — hint to allow optimizations
set.stream()
    .unordered()  // Allow reordering for parallel performance
    .limit(10)
    .collect(toList());

// Stream reuse — CANNOT reuse stream
Stream<String> stream = names.stream();
stream.forEach(System.out::println);
// stream.count();  // IllegalStateException: stream has already been operated upon","language":"java"},{"type":"heading","level":2,"text":"Keyword: Collectors — Advanced"},{"type":"paragraph","text":"**Định nghĩa:** Collectors cho complex aggregation — grouping, partitioning, downstream collectors."},{"type":"code_block","code":"List<Employee> employees = getEmployees();

// groupingBy with downstream collector
Map<Department, Double> avgSalaryByDept = employees.stream()
    .collect(Collectors.groupingBy(
        Employee::getDepartment,
        Collectors.averagingDouble(Employee::getSalary)
    ));

// Multi-level grouping
Map<Department, Map<Level, List<Employee>>> grouped = employees.stream()
    .collect(Collectors.groupingBy(
        Employee::getDepartment,
        Collectors.groupingBy(Employee::getLevel)
    ));

// groupingBy + counting + sorting
Map<Department, Long> countByDept = employees.stream()
    .collect(Collectors.groupingBy(Employee::getDepartment, Collectors.counting()));

// toMap with merge function (handle duplicate keys)
Map<String, Employee> byName = employees.stream()
    .collect(Collectors.toMap(
        Employee::getName,
        Function.identity(),
        (existing, replacement) -> existing  // Keep first on duplicate
    ));

// toMap with specific Map implementation
Map<String, Employee> sortedByName = employees.stream()
    .collect(Collectors.toMap(
        Employee::getName,
        Function.identity(),
        (a, b) -> a,
        TreeMap::new  // Sorted map
    ));

// Custom collector
Collector<String, StringBuilder, String> joining = Collector.of(
    StringBuilder::new,           // Supplier: create accumulator
    StringBuilder::append,        // Accumulator: add element
    (a, b) -> a.append(b),      // Combiner: merge accumulators (parallel)
    StringBuilder::toString       // Finisher: extract result
);

// teeing collector (Java 12+) — two collectors in one pass
var result = employees.stream().collect(
    Collectors.teeing(
        Collectors.averagingDouble(Employee::getSalary),
        Collectors.counting(),
        (avg, count) -> "Average: " + avg + ", Count: " + count
    )
);","language":"java"},{"type":"heading","level":2,"text":"Keyword: Parallel Streams — Pitfalls"},{"type":"paragraph","text":"**Định nghĩa:** Parallel stream dùng ForkJoinPool — nhưng không phải lúc nào cũng nhanh hơn."},{"type":"code_block","code":"// Parallel stream dùng common ForkJoinPool
// Default parallelism = Runtime.getRuntime().availableProcessors() - 1

// Khi NÊN dùng parallel:
// 1. Large dataset (>10,000 elements)
// 2. CPU-intensive operations (không I/O)
// 3. Stateless, non-interfering operations
// 4. Source hỗ trợ efficient splitting (ArrayList, array, IntRange)

// Khi KHÔNG NÊN dùng parallel:
// 1. Small dataset — overhead > benefit
// 2. I/O operations — threads block, pool exhausted
// 3. Ordered operations (limit, findFirst) — coordination overhead
// 4. LinkedList source — poor splitting (O(n) to split)
// 5. Shared mutable state — race conditions

// ❌ Race condition
List<String> results = new ArrayList<>();  // Not thread-safe!
stream.parallel().forEach(item -> results.add(process(item)));  // BUG!

// ✅ Thread-safe collection
List<String> results = stream.parallel()
    .map(this::process)
    .collect(Collectors.toList());  // Collector handles thread-safety

// ❌ Common ForkJoinPool starvation
// Blocking I/O in parallel stream blocks shared pool threads
stream.parallel().forEach(item -> {
    httpClient.send(request);  // Blocks thread!
    // Other parallel streams in application starved
});

// ✅ Custom ForkJoinPool for isolation
ForkJoinPool customPool = new ForkJoinPool(4);
List<Result> results = customPool.submit(() ->
    items.parallelStream()
        .map(this::process)
        .collect(toList())
).get();
customPool.shutdown();

// Spliterator — controls how stream splits for parallel
// ArrayList: splits in half → good parallelism
// LinkedList: splits poorly → sequential fallback
// TreeSet: splits by subtree → decent parallelism
// Custom Spliterator for custom data sources","language":"java"},{"type":"heading","level":2,"text":"Keyword: Optional — Best Practices"},{"type":"paragraph","text":"**Định nghĩa:** Container cho nullable values — dùng đúng cách tránh anti-patterns."},{"type":"code_block","code":"// ✅ DO: Return Optional from methods that may not have result
public Optional<User> findById(Long id) {
    return Optional.ofNullable(userMap.get(id));
}

// ✅ DO: Chain operations
String city = findUser(id)
    .flatMap(User::getAddress)
    .map(Address::getCity)
    .orElse("Unknown");

// ✅ DO: Use orElseGet for expensive defaults
user.orElseGet(() -> loadDefaultUser());  // Lazy — only called if empty

// ❌ DON'T: Use Optional as field type
public class User {
    private Optional<String> middleName;  // BAD — not serializable, overhead
    private String middleName;  // GOOD — nullable field is fine
}

// ❌ DON'T: Use Optional as method parameter
public void process(Optional<String> name) { }  // BAD
public void process(String name) { }  // GOOD — caller passes null or value
public void process() { }  // GOOD — overload for absent case

// ❌ DON'T: Use Optional.get() without check
user.get();  // NoSuchElementException if empty!
// ✅
user.orElseThrow();  // Same exception but intent is clear
user.orElseThrow(() -> new UserNotFoundException(id));

// ❌ DON'T: Use Optional for collections
public Optional<List<User>> findUsers() { }  // BAD
public List<User> findUsers() { return List.of(); }  // GOOD — empty list

// ❌ DON'T: isPresent() + get() pattern
if (user.isPresent()) {
    process(user.get());  // BAD — verbose
}
user.ifPresent(this::process);  // GOOD

// Optional with streams (Java 9+)
optional.stream()  // Stream of 0 or 1 elements
    .flatMap(...)
    .collect(...);

// or() (Java 9+) — chain Optional suppliers
Optional<User> user = findInCache(id)
    .or(() -> findInDatabase(id))
    .or(() -> findInRemoteService(id));","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Concurrency & Multithreading — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Concurrency là lĩnh vực phức tạp nhất trong Java. Senior/Tech Lead cần hiểu Java Memory Model (JMM), happens-before relationships, lock-free algorithms, và modern concurrency patterns."},{"type":"heading","level":2,"text":"Keyword: Java Memory Model (JMM)"},{"type":"paragraph","text":"**Định nghĩa:** JMM (JSR 133) định nghĩa cách threads tương tác qua shared memory — visibility và ordering guarantees."},{"type":"code_block","code":"// Problem: Mỗi thread có thể cache variables trong CPU registers/L1 cache
// → Thread A ghi x=1, Thread B có thể vẫn thấy x=0

// JMM defines "happens-before" relationships:
// Nếu action A happens-before action B → B thấy kết quả của A

// Happens-before rules:
// 1. Program order: trong cùng thread, statement trước HB statement sau
// 2. Monitor lock: unlock() HB lock() tiếp theo trên cùng monitor
// 3. Volatile: write HB read tiếp theo trên cùng volatile variable
// 4. Thread start: thread.start() HB mọi action trong thread đó
// 5. Thread join: mọi action trong thread HB join() return
// 6. Transitivity: A HB B, B HB C → A HB C

// Visibility problem:
public class Visibility {
    private boolean running = true;  // Không volatile!

    public void stop() { running = false; }

    public void run() {
        while (running) {  // Có thể loop mãi mãi!
            // JIT có thể hoist: if (running) while(true) { }
        }
    }
}

// Fix 1: volatile
private volatile boolean running = true;
// volatile write → flush to main memory
// volatile read → read from main memory
// + prevents reordering around volatile access

// Fix 2: synchronized
public synchronized void stop() { running = false; }
public void run() {
    while (true) {
        synchronized (this) {
            if (!running) break;
        }
    }
}

// Reordering — compiler/CPU có thể reorder instructions
int a = 0, b = 0;
// Thread 1:        Thread 2:
a = 1;              int x = b;
b = 2;              int y = a;
// Possible result: x=2, y=0 (reordering!)
// volatile hoặc synchronized ngăn reordering","language":"java"},{"type":"heading","level":2,"text":"Keyword: synchronized — Monitor Lock"},{"type":"paragraph","text":"**Định nghĩa:** Intrinsic lock (monitor) — mutual exclusion + memory visibility."},{"type":"code_block","code":"// Mỗi object có 1 intrinsic lock (monitor)
// synchronized block: acquire lock → execute → release lock

// Lock levels (JVM optimization):
// 1. Biased locking: assume single thread → no CAS (deprecated Java 15+)
// 2. Thin lock (lightweight): CAS on mark word → fast for low contention
// 3. Fat lock (heavyweight): OS mutex → slow but fair for high contention

// Lock escalation: biased → thin → fat (automatic, based on contention)

// synchronized method vs block:
public synchronized void method() { }  // Lock on 'this'
public static synchronized void staticMethod() { }  // Lock on Class object

public void method() {
    synchronized (this) { }  // Same as synchronized method
    synchronized (lockObject) { }  // Lock on specific object — preferred
}

// ❌ Common mistakes:
// 1. Synchronize on wrong object
private final List<String> list = new ArrayList<>();
synchronized (list) { list.add("item"); }
// Nếu list được reassign → different lock → race condition!
// Fix: dùng separate final lock object

private final Object lock = new Object();
synchronized (lock) { list.add("item"); }

// 2. Synchronize on boxed primitive
private Integer count = 0;
synchronized (count) { count++; }  // ⚠️ count = new Integer → different object!

// 3. Double-checked locking (broken without volatile)
// ❌ Broken:
private static Singleton instance;
public static Singleton getInstance() {
    if (instance == null) {
        synchronized (Singleton.class) {
            if (instance == null) {
                instance = new Singleton();  // May be reordered!
                // Other thread may see non-null but partially constructed instance
            }
        }
    }
    return instance;
}

// ✅ Fixed with volatile:
private static volatile Singleton instance;
// volatile prevents reordering of constructor and assignment

// ✅ Better: Initialization-on-demand holder
public class Singleton {
    private Singleton() {}
    private static class Holder {
        static final Singleton INSTANCE = new Singleton();
    }
    public static Singleton getInstance() { return Holder.INSTANCE; }
}
// Class loading guarantees thread-safety + lazy initialization","language":"java"},{"type":"heading","level":2,"text":"Keyword: java.util.concurrent — Lock Framework"},{"type":"paragraph","text":"**Định nghĩa:** Explicit locks với more features than synchronized — tryLock, fairness, read-write separation."},{"type":"code_block","code":"// ReentrantLock — explicit lock with more control
ReentrantLock lock = new ReentrantLock();
lock.lock();
try {
    // Critical section
} finally {
    lock.unlock();  // MUST unlock in finally
}

// tryLock — non-blocking attempt
if (lock.tryLock(1, TimeUnit.SECONDS)) {
    try { /* critical section */ }
    finally { lock.unlock(); }
} else {
    // Could not acquire lock — handle gracefully
}

// ReadWriteLock — multiple readers OR single writer
ReadWriteLock rwLock = new ReentrantReadWriteLock();
// Multiple threads can read simultaneously
rwLock.readLock().lock();
try { return cache.get(key); }
finally { rwLock.readLock().unlock(); }

// Only one thread can write, blocks all readers
rwLock.writeLock().lock();
try { cache.put(key, value); }
finally { rwLock.writeLock().unlock(); }

// StampedLock (Java 8+) — optimistic reading
StampedLock sl = new StampedLock();

// Optimistic read — no locking, validate after
long stamp = sl.tryOptimisticRead();
double x = this.x, y = this.y;  // Read fields
if (!sl.validate(stamp)) {  // Check if write occurred
    stamp = sl.readLock();  // Fallback to pessimistic read
    try { x = this.x; y = this.y; }
    finally { sl.unlockRead(stamp); }
}
// Use x, y

// Condition — wait/notify replacement
ReentrantLock lock = new ReentrantLock();
Condition notEmpty = lock.newCondition();
Condition notFull = lock.newCondition();

// Producer:
lock.lock();
try {
    while (queue.isFull()) notFull.await();
    queue.add(item);
    notEmpty.signal();
} finally { lock.unlock(); }

// Consumer:
lock.lock();
try {
    while (queue.isEmpty()) notEmpty.await();
    item = queue.remove();
    notFull.signal();
} finally { lock.unlock(); }","language":"java"},{"type":"heading","level":2,"text":"Keyword: Atomic Classes & CAS"},{"type":"paragraph","text":"**Định nghĩa:** Lock-free thread-safe operations dùng Compare-And-Swap (CAS) — nhanh hơn synchronized cho simple operations."},{"type":"code_block","code":"// CAS: compareAndSet(expected, new)
// Hardware instruction: nếu current == expected → set new, return true
// Nếu current != expected → do nothing, return false (retry)

AtomicInteger counter = new AtomicInteger(0);
counter.incrementAndGet();     // ++counter (atomic)
counter.getAndIncrement();     // counter++ (atomic)
counter.addAndGet(5);          // counter += 5 (atomic)
counter.compareAndSet(10, 20); // if counter==10 then counter=20

// AtomicReference — CAS cho object references
AtomicReference<Config> config = new AtomicReference<>(initialConfig);
config.compareAndSet(oldConfig, newConfig);

// LongAdder (Java 8+) — faster than AtomicLong for high contention
// Internally: array of cells, each thread updates different cell
// sum() aggregates all cells
LongAdder adder = new LongAdder();
adder.increment();  // Distributed across cells
adder.sum();        // Aggregate

// Benchmark: 16 threads incrementing
// AtomicLong: ~200M ops/sec (contention on single variable)
// LongAdder: ~1.5B ops/sec (distributed, less contention)

// VarHandle (Java 9+) — low-level atomic access
// Replacement for sun.misc.Unsafe
// Used internally by AtomicXxx classes","language":"java"},{"type":"heading","level":2,"text":"Keyword: CompletableFuture — Async Programming"},{"type":"paragraph","text":"**Định nghĩa:** Composable async operations — Java's answer to Promises/Futures."},{"type":"code_block","code":"// Async execution
CompletableFuture<User> userFuture = CompletableFuture.supplyAsync(() ->
    userService.findById(userId)  // Runs in ForkJoinPool.commonPool()
);

// Chaining
CompletableFuture<String> result = userFuture
    .thenApply(user -> user.getEmail())           // Transform (same thread)
    .thenApplyAsync(email -> enrichEmail(email))   // Transform (async)
    .thenCompose(email -> sendEmailAsync(email))   // FlatMap (async → async)
    .exceptionally(ex -> {
        logger.error("Failed", ex);
        return "fallback@example.com";
    });

// Combining multiple futures
CompletableFuture<User> userF = fetchUserAsync(id);
CompletableFuture<List<Order>> ordersF = fetchOrdersAsync(id);
CompletableFuture<Double> balanceF = fetchBalanceAsync(id);

// Wait for all
CompletableFuture.allOf(userF, ordersF, balanceF)
    .thenRun(() -> {
        User user = userF.join();
        List<Order> orders = ordersF.join();
        Double balance = balanceF.join();
        // All available
    });

// Wait for any (first to complete)
CompletableFuture.anyOf(primaryService, fallbackService)
    .thenAccept(result -> process(result));

// Timeout (Java 9+)
userFuture
    .orTimeout(5, TimeUnit.SECONDS)           // TimeoutException if not done
    .completeOnTimeout(defaultUser, 5, TimeUnit.SECONDS);  // Default value

// Error handling patterns
CompletableFuture<Result> robustCall = CompletableFuture
    .supplyAsync(() -> callService())
    .handle((result, ex) -> {
        if (ex != null) {
            logger.error("Service call failed", ex);
            return Result.empty();
        }
        return result;
    });

// Custom executor (avoid common pool for I/O)
ExecutorService ioPool = Executors.newFixedThreadPool(20);
CompletableFuture.supplyAsync(() -> httpCall(), ioPool);

// Virtual Threads (Java 21+) — lightweight threads for I/O
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    List<Future<String>> futures = urls.stream()
        .map(url -> executor.submit(() -> fetchUrl(url)))
        .toList();
    // Millions of virtual threads — no pool sizing needed
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Virtual Threads (Java 21+)"},{"type":"paragraph","text":"**Định nghĩa:** Lightweight threads managed by JVM — millions of concurrent threads cho I/O-bound workloads."},{"type":"code_block","code":"// Platform thread: 1:1 mapping to OS thread (~1MB stack, expensive)
// Virtual thread: M:N mapping (many virtual → few platform), ~1KB stack

// Create virtual threads
Thread vt = Thread.ofVirtual().start(() -> {
    // Runs on virtual thread
    // When blocked (I/O, sleep) → unmounts from platform thread
    // Platform thread freed for other virtual threads
});

// Executor with virtual threads
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    // Submit 100,000 tasks — each gets own virtual thread
    IntStream.range(0, 100_000).forEach(i ->
        executor.submit(() -> {
            Thread.sleep(Duration.ofSeconds(1));  // Doesn't block platform thread!
            return fetchData(i);
        })
    );
}

// When to use virtual threads:
// ✅ I/O-bound: HTTP calls, database queries, file I/O
// ✅ High concurrency: thousands of concurrent connections
// ❌ CPU-bound: computation-heavy tasks (use platform threads)
// ❌ With synchronized blocks holding locks during I/O (pinning)

// Pinning — virtual thread stuck on platform thread:
// 1. Inside synchronized block (use ReentrantLock instead)
// 2. Inside native method
// -Djdk.tracePinnedThreads=full to detect

// Structured Concurrency (Preview, Java 21+)
try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
    Subtask<User> user = scope.fork(() -> findUser(id));
    Subtask<List<Order>> orders = scope.fork(() -> findOrders(id));

    scope.join();           // Wait for all
    scope.throwIfFailed();  // Propagate exceptions

    return new UserProfile(user.get(), orders.get());
}
// If any subtask fails → all others cancelled automatically
// Parent-child relationship: no leaked threads","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Annotations & Reflection — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Annotations và Reflection là nền tảng của Spring Framework, Hibernate, Jackson, và hầu hết Java frameworks. Senior cần hiểu annotation processing pipeline, reflection performance, và cách frameworks dùng chúng."},{"type":"heading","level":2,"text":"Keyword: Annotation Processing Pipeline"},{"type":"paragraph","text":"**Định nghĩa:** Annotations được xử lý ở 3 giai đoạn: compile-time (APT), class-loading, và runtime (reflection)."},{"type":"code_block","code":"// @Retention xác định khi nào annotation tồn tại:

// SOURCE — chỉ trong source code, compiler xóa
// Dùng cho: code generation, lint checks
@Retention(RetentionPolicy.SOURCE)
public @interface Generated { }  // Lombok @Getter, @Setter

// CLASS — trong .class file, nhưng JVM không load
// Dùng cho: bytecode analysis tools
@Retention(RetentionPolicy.CLASS)  // Default nếu không chỉ định
public @interface NonNull { }

// RUNTIME — tồn tại tại runtime, đọc được qua reflection
// Dùng cho: Spring, Hibernate, Jackson, JUnit
@Retention(RetentionPolicy.RUNTIME)
public @interface Service { }

// Compile-time annotation processing (APT):
// javax.annotation.processing.AbstractProcessor
// Chạy trong compiler → generate source code
// Ví dụ: Lombok, MapStruct, Dagger, AutoValue

// Lombok @Getter generates:
@Getter
public class User {
    private String name;
}
// APT generates bytecode for:
// public String getName() { return this.name; }

// Runtime annotation processing:
// Spring scans classpath → find @Component, @Service, etc.
// Hibernate reads @Entity, @Column → build mapping
// Jackson reads @JsonProperty → configure serialization","language":"java"},{"type":"heading","level":2,"text":"Keyword: Custom Annotation Design"},{"type":"paragraph","text":"**Định nghĩa:** Thiết kế annotation cho framework/library — meta-annotations, repeatable, inherited."},{"type":"code_block","code":"// Full-featured custom annotation
@Retention(RetentionPolicy.RUNTIME)
@Target({ElementType.METHOD, ElementType.TYPE})
@Documented  // Include in Javadoc
@Inherited   // Subclass inherits this annotation
public @interface Cacheable {
    String value() default "";           // Cache name
    long ttl() default 300;              // TTL in seconds
    String key() default "";             // SpEL expression for cache key
    String condition() default "";       // Conditional caching
    Class<? extends CacheResolver> resolver() default DefaultCacheResolver.class;
}

// Usage:
@Cacheable(value = "users", ttl = 600, key = "#id")
public User findById(Long id) { }

// Repeatable annotation (Java 8+)
@Repeatable(Schedules.class)
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
public @interface Schedule {
    String cron();
}

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
public @interface Schedules {
    Schedule[] value();
}

// Usage:
@Schedule(cron = "0 0 * * *")
@Schedule(cron = "0 12 * * *")
public void cleanup() { }

// Composed annotation (meta-annotation pattern)
// Spring uses this extensively
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
@Service                    // Meta-annotation
@Transactional              // Meta-annotation
public @interface TransactionalService {
    // Combines @Service + @Transactional
}

@TransactionalService  // = @Service + @Transactional
public class OrderService { }","language":"java"},{"type":"heading","level":2,"text":"Keyword: Reflection — Performance & Alternatives"},{"type":"paragraph","text":"**Định nghĩa:** Reflection cho phép inspect/modify code tại runtime — powerful nhưng có performance cost."},{"type":"code_block","code":"// Reflection performance cost:
// 1. No JIT optimization (cannot inline reflective calls)
// 2. Security checks on every access
// 3. Boxing/unboxing for primitive parameters
// 4. Array creation for varargs

// Benchmark: direct call vs reflection
// Direct: ~1-2 ns
// Reflection (first call): ~1000 ns
// Reflection (cached Method): ~50-100 ns
// MethodHandle: ~5-10 ns

// Optimization 1: Cache Method/Field objects
// ❌ Slow: lookup every time
for (Object obj : objects) {
    Method m = obj.getClass().getMethod("getName");
    m.invoke(obj);
}

// ✅ Fast: cache Method object
Method getName = User.class.getMethod("getName");
getName.setAccessible(true);  // Skip access checks → faster
for (Object obj : objects) {
    getName.invoke(obj);
}

// Optimization 2: MethodHandle (Java 7+)
// Closer to direct call performance, JIT can optimize
MethodHandles.Lookup lookup = MethodHandles.lookup();
MethodHandle mh = lookup.findVirtual(User.class, "getName",
    MethodType.methodType(String.class));

for (Object obj : objects) {
    String name = (String) mh.invoke(obj);  // Near-direct-call speed
}

// Optimization 3: LambdaMetafactory — fastest reflective access
// Generate lambda at runtime that calls method directly
MethodHandle mh = lookup.findVirtual(User.class, "getName",
    MethodType.methodType(String.class));

CallSite site = LambdaMetafactory.metafactory(
    lookup, "apply", MethodType.methodType(Function.class),
    MethodType.methodType(Object.class, Object.class),
    mh, MethodType.methodType(String.class, User.class)
);

@SuppressWarnings("unchecked")
Function<User, String> getter = (Function<User, String>) site.getTarget().invokeExact();
// getter.apply(user) → same speed as user.getName()

// Spring Framework uses this approach for property access
// → Reflection overhead only at startup, not at runtime

// Module system restrictions (Java 9+):
// Reflection on non-exported packages → IllegalAccessException
// Fix: --add-opens module/package=ALL-UNNAMED
// Or: opens package in module-info.java","language":"java"},{"type":"heading","level":2,"text":"Keyword: Dynamic Proxy"},{"type":"paragraph","text":"**Định nghĩa:** Tạo proxy object tại runtime implement interfaces — nền tảng của Spring AOP."},{"type":"code_block","code":"// JDK Dynamic Proxy — chỉ cho interfaces
public interface UserService {
    User findById(Long id);
    void save(User user);
}

// InvocationHandler — intercept mọi method call
InvocationHandler handler = (proxy, method, args) -> {
    long start = System.nanoTime();
    try {
        Object result = method.invoke(realService, args);  // Call real method
        return result;
    } finally {
        long duration = System.nanoTime() - start;
        logger.info("{} took {} ms", method.getName(), duration / 1_000_000.0);
    }
};

UserService proxy = (UserService) Proxy.newProxyInstance(
    UserService.class.getClassLoader(),
    new Class[]{UserService.class},
    handler
);

proxy.findById(1L);  // Intercepted → logged → delegated to real service

// CGLIB Proxy — cho classes (không cần interface)
// Spring dùng CGLIB khi target không implement interface
// Tạo subclass tại runtime → override methods
// Limitation: cannot proxy final classes/methods

// Spring AOP uses:
// JDK Proxy: khi bean implement interface
// CGLIB: khi bean không implement interface
// spring.aop.proxy-target-class=true → force CGLIB cho tất cả

// Practical use cases:
// 1. Logging/Monitoring (cross-cutting concern)
// 2. Transaction management (@Transactional)
// 3. Security checks (@PreAuthorize)
// 4. Caching (@Cacheable)
// 5. Retry logic (@Retryable)
// 6. Lazy loading (Hibernate entity proxies)","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Spring IoC & Dependency Injection — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"IoC Container là trái tim của Spring — quản lý object lifecycle, dependency wiring, và configuration. Senior cần hiểu container internals, bean resolution algorithm, circular dependency handling, và advanced DI patterns."},{"type":"heading","level":2,"text":"Keyword: IoC Container Internals"},{"type":"paragraph","text":"**Định nghĩa:** Spring Container = BeanFactory + ApplicationContext — quản lý bean definitions, instantiation, wiring, và lifecycle."},{"type":"code_block","code":"// Container startup sequence:
// 1. Load bean definitions (XML, annotations, Java config)
// 2. BeanFactoryPostProcessor — modify bean definitions
//    Ví dụ: PropertySourcesPlaceholderConfigurer resolve ${...}
// 3. Instantiate beans (constructor)
// 4. Populate properties (setter injection, field injection)
// 5. BeanPostProcessor.postProcessBeforeInitialization
//    Ví dụ: @Autowired resolution, @Value resolution
// 6. InitializingBean.afterPropertiesSet() / @PostConstruct
// 7. BeanPostProcessor.postProcessAfterInitialization
//    Ví dụ: AOP proxy creation, @Async proxy
// 8. Bean ready to use
// ...
// 9. @PreDestroy / DisposableBean.destroy()
// 10. Container shutdown

// BeanFactory vs ApplicationContext:
// BeanFactory: lazy initialization, basic DI
// ApplicationContext: eager initialization + events + i18n + AOP + ...
// → Luôn dùng ApplicationContext trong production

// Bean Definition:
// - Class name
// - Scope (singleton, prototype, request, session)
// - Constructor arguments
// - Property values
// - Init/destroy methods
// - Dependencies (autowire candidates)

// Component scanning:
@ComponentScan(
    basePackages = "com.example",
    excludeFilters = @ComponentScan.Filter(
        type = FilterType.REGEX,
        pattern = "com\\.example\\.internal\\..*"
    )
)
// Scans classpath → finds @Component, @Service, @Repository, @Controller
// Creates BeanDefinition for each → registers in container","language":"java"},{"type":"heading","level":2,"text":"Keyword: Dependency Injection — Advanced Patterns"},{"type":"paragraph","text":"**Định nghĩa:** Ngoài basic constructor/setter/field injection, Spring hỗ trợ nhiều patterns phức tạp."},{"type":"code_block","code":"// 1. Constructor Injection — BEST PRACTICE
@Service
public class OrderService {
    private final OrderRepository repository;
    private final PaymentService paymentService;
    private final NotificationService notificationService;

    // Single constructor → @Autowired implicit (Spring 4.3+)
    public OrderService(OrderRepository repository,
                        PaymentService paymentService,
                        NotificationService notificationService) {
        this.repository = repository;
        this.paymentService = paymentService;
        this.notificationService = notificationService;
    }
}
// Advantages: immutable (final), testable, explicit dependencies
// Disadvantage: many parameters → consider refactoring (SRP violation?)

// 2. Optional Dependencies
@Service
public class ReportService {
    private final DataSource dataSource;
    private final CacheManager cacheManager;  // Optional

    public ReportService(DataSource dataSource,
                         @Autowired(required = false) CacheManager cacheManager) {
        this.dataSource = dataSource;
        this.cacheManager = cacheManager;  // null if no CacheManager bean
    }

    // Hoặc dùng Optional
    public ReportService(DataSource dataSource, Optional<CacheManager> cacheManager) {
        this.dataSource = dataSource;
        this.cacheManager = cacheManager.orElse(null);
    }
}

// 3. Collection Injection — inject tất cả implementations
@Service
public class NotificationService {
    private final List<NotificationChannel> channels;

    // Spring inject TẤT CẢ beans implement NotificationChannel
    // Ordered by @Order annotation hoặc Ordered interface
    public NotificationService(List<NotificationChannel> channels) {
        this.channels = channels;
    }

    public void notifyAll(String message) {
        channels.forEach(ch -> ch.send(message));
    }
}

// 4. Map Injection — inject by name
@Service
public class StrategyService {
    private final Map<String, PaymentStrategy> strategies;

    // Key = bean name, Value = bean instance
    public StrategyService(Map<String, PaymentStrategy> strategies) {
        this.strategies = strategies;
    }

    public void pay(String type, BigDecimal amount) {
        PaymentStrategy strategy = strategies.get(type);
        if (strategy == null) throw new IllegalArgumentException("Unknown: " + type);
        strategy.pay(amount);
    }
}

// 5. ObjectProvider — lazy/optional/stream access
@Service
public class LazyService {
    private final ObjectProvider<ExpensiveBean> expensiveProvider;

    public LazyService(ObjectProvider<ExpensiveBean> expensiveProvider) {
        this.expensiveProvider = expensiveProvider;
    }

    public void process() {
        // Lazy: bean created only when getObject() called
        ExpensiveBean bean = expensiveProvider.getIfAvailable();
        if (bean != null) bean.doWork();

        // Stream all beans of type
        expensiveProvider.stream().forEach(ExpensiveBean::doWork);

        // With default
        ExpensiveBean bean = expensiveProvider.getIfAvailable(DefaultExpensiveBean::new);
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Bean Resolution & Ambiguity"},{"type":"paragraph","text":"**Định nghĩa:** Cách Spring chọn bean khi có nhiều candidates — @Primary, @Qualifier, custom qualifiers."},{"type":"code_block","code":"// Khi có nhiều beans cùng type:
public interface Cache {
    void put(String key, Object value);
    Object get(String key);
}

@Service("localCache")
public class LocalCache implements Cache { }

@Service("redisCache")
@Primary  // Default choice khi không chỉ định
public class RedisCache implements Cache { }

@Service("memcachedCache")
public class MemcachedCache implements Cache { }

// Resolution order:
// 1. @Qualifier match
// 2. @Primary
// 3. Bean name match (parameter name = bean name)
// 4. If still ambiguous → NoUniqueBeanDefinitionException

// @Qualifier
@Service
public class UserService {
    public UserService(@Qualifier("localCache") Cache cache) { }
}

// Custom qualifier annotation — type-safe, refactor-friendly
@Qualifier
@Retention(RetentionPolicy.RUNTIME)
@Target({ElementType.FIELD, ElementType.PARAMETER, ElementType.TYPE})
public @interface CacheType {
    String value();
}

@Service
@CacheType("local")
public class LocalCache implements Cache { }

@Service
public class UserService {
    public UserService(@CacheType("local") Cache cache) { }
}

// Profile-based selection
@Service
@Profile("dev")
public class InMemoryCache implements Cache { }

@Service
@Profile("prod")
public class RedisCache implements Cache { }

// @ConditionalOnProperty — Spring Boot
@Service
@ConditionalOnProperty(name = "cache.type", havingValue = "redis")
public class RedisCache implements Cache { }","language":"java"},{"type":"heading","level":2,"text":"Keyword: Circular Dependencies"},{"type":"paragraph","text":"**Định nghĩa:** A depends on B, B depends on A — Spring có thể resolve cho setter/field injection nhưng KHÔNG cho constructor injection."},{"type":"code_block","code":"// ❌ Circular dependency với constructor injection → BeanCurrentlyInCreationException
@Service
public class ServiceA {
    public ServiceA(ServiceB b) { }  // Needs B
}

@Service
public class ServiceB {
    public ServiceB(ServiceA a) { }  // Needs A → deadlock!
}

// Spring resolution cho setter/field injection:
// 1. Create A (without dependencies)
// 2. Put A reference in "early singleton cache" (3rd level cache)
// 3. Create B
// 4. Inject A reference into B (from early cache)
// 5. B fully initialized
// 6. Inject B into A
// 7. A fully initialized

// Three-level cache:
// singletonObjects (1st): fully initialized beans
// earlySingletonObjects (2nd): early reference (after instantiation, before population)
// singletonFactories (3rd): ObjectFactory to create early reference

// ❌ Circular dependency là design smell — refactor!
// Fix 1: Extract shared logic into third service
@Service
public class SharedLogic { }

@Service
public class ServiceA {
    public ServiceA(SharedLogic shared) { }
}

@Service
public class ServiceB {
    public ServiceB(SharedLogic shared) { }
}

// Fix 2: Use events for decoupling
@Service
public class OrderService {
    private final ApplicationEventPublisher publisher;

    public void createOrder(Order order) {
        orderRepo.save(order);
        publisher.publishEvent(new OrderCreatedEvent(order));
    }
}

@Service
public class InventoryService {
    @EventListener
    public void onOrderCreated(OrderCreatedEvent event) {
        // React to order creation without direct dependency
    }
}

// Fix 3: @Lazy — defer initialization
@Service
public class ServiceA {
    public ServiceA(@Lazy ServiceB b) { }  // Proxy injected, real B created later
}

// Spring Boot 2.6+ disables circular dependencies by default
// spring.main.allow-circular-references=true to re-enable (not recommended)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Bean Scope — Deep Dive"},{"type":"paragraph","text":"**Định nghĩa:** Scope xác định lifecycle và sharing behavior của beans."},{"type":"code_block","code":"// Singleton (default): 1 instance per container
// → Stateless services, repositories, configurations
// ⚠️ KHÔNG lưu request-specific state trong singleton bean!

// Prototype: new instance mỗi lần inject/getBean
// → Stateful objects, builders
// ⚠️ Container KHÔNG quản lý lifecycle (không gọi @PreDestroy)

// Request: 1 instance per HTTP request (web only)
@Scope(value = WebApplicationContext.SCOPE_REQUEST, proxyMode = ScopedProxyMode.TARGET_CLASS)
@Component
public class RequestContext {
    private String correlationId;
    // Mỗi request có instance riêng
}

// Session: 1 instance per HTTP session (web only)
// Application: 1 instance per ServletContext

// Scope proxy — inject shorter-lived bean into longer-lived bean
// Problem: Singleton bean holds reference to request-scoped bean
// → Cùng 1 request bean cho mọi requests!

// Solution: Scoped proxy
@Component
@Scope(value = "request", proxyMode = ScopedProxyMode.TARGET_CLASS)
public class RequestData { }

@Service  // Singleton
public class MyService {
    private final RequestData requestData;  // Proxy injected!
    // Proxy delegates to actual request-scoped instance per request
}

// Custom scope
public class TenantScope implements Scope {
    @Override
    public Object get(String name, ObjectFactory<?> objectFactory) {
        String tenantId = TenantContext.getCurrentTenant();
        Map<String, Object> tenantBeans = tenantScopedBeans.get(tenantId);
        return tenantBeans.computeIfAbsent(name, k -> objectFactory.getObject());
    }
    // 1 instance per tenant
}","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Spring AOP — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"AOP tách cross-cutting concerns khỏi business logic. Senior cần hiểu proxy mechanism, pointcut expressions, advice ordering, và self-invocation trap."},{"type":"heading","level":2,"text":"Keyword: AOP Proxy Mechanism"},{"type":"paragraph","text":"**Định nghĩa:** Spring AOP dùng runtime proxies — JDK Dynamic Proxy hoặc CGLIB."},{"type":"code_block","code":"// JDK Dynamic Proxy: target implements interface
// → Proxy implements same interface, delegates to target
// Limitation: chỉ intercept interface methods

// CGLIB Proxy: target không implement interface
// → Proxy extends target class, override methods
// Limitation: cannot proxy final classes/methods

// Spring Boot default: CGLIB cho tất cả (spring.aop.proxy-target-class=true)

// Self-invocation trap — BUG PHỔ BIẾN NHẤT với AOP
@Service
public class UserService {
    @Transactional
    public void createUser(User user) {
        userRepo.save(user);
        sendWelcomeEmail(user);  // ⚠️ Self-invocation!
    }

    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void sendWelcomeEmail(User user) {
        // @Transactional KHÔNG hoạt động!
        // Vì gọi trực tiếp this.sendWelcomeEmail()
        // Proxy bị bypass → AOP advice không chạy
    }
}

// Tại sao? Proxy wraps target:
// Client → Proxy.createUser() → Target.createUser()
//                                  → Target.sendWelcomeEmail() ← direct call, no proxy!

// Fix 1: Inject self (circular, cần @Lazy)
@Service
public class UserService {
    @Lazy @Autowired private UserService self;

    public void createUser(User user) {
        userRepo.save(user);
        self.sendWelcomeEmail(user);  // Goes through proxy ✓
    }
}

// Fix 2: Extract to separate service
@Service
public class EmailService {
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void sendWelcomeEmail(User user) { }
}

// Fix 3: ApplicationContext.getBean()
// Fix 4: AopContext.currentProxy() (cần exposeProxy=true)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Pointcut Expressions — Advanced"},{"type":"paragraph","text":"**Định nghĩa:** Pointcut language xác định WHERE advice applies — execution, annotation, within, args."},{"type":"code_block","code":"// execution — most common, match method execution
@Pointcut("execution(public * com.example.service.*.*(..))")
// Breakdown:
// public — access modifier (optional)
// * — any return type
// com.example.service.* — any class in package
// .* — any method
// (..) — any parameters

// Wildcards:
// * — matches any single element
// .. — matches any number of elements (packages or parameters)
// + — matches subclasses

// Examples:
@Pointcut("execution(* save*(..))") // Any method starting with "save"
@Pointcut("execution(* *(.., String))") // Last param is String
@Pointcut("execution(* com.example..*.*(..))") // Any method in com.example and sub-packages

// @annotation — match methods with specific annotation
@Pointcut("@annotation(com.example.Loggable)")
// Matches any method annotated with @Loggable

// @within — match all methods in class with annotation
@Pointcut("@within(org.springframework.stereotype.Service)")
// All methods in @Service classes

// within — match all methods in class/package
@Pointcut("within(com.example.service..*)")
// All methods in service package and sub-packages

// args — match by parameter types (runtime check)
@Pointcut("args(String, ..)")
// Methods where first arg is String at runtime

// Combining pointcuts
@Pointcut("serviceLayer() && !execution(* toString())")
@Pointcut("execution(* *(..)) && @annotation(transactional)")

// Binding annotations to advice parameters
@Around("@annotation(cacheable)")
public Object cache(ProceedingJoinPoint pjp, Cacheable cacheable) throws Throwable {
    String cacheName = cacheable.value();
    long ttl = cacheable.ttl();
    // Use annotation attributes
    String key = generateKey(pjp, cacheable.key());
    Object cached = cacheManager.get(cacheName, key);
    if (cached != null) return cached;
    Object result = pjp.proceed();
    cacheManager.put(cacheName, key, result, ttl);
    return result;
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Advice Ordering & @Transactional Internals"},{"type":"paragraph","text":"**Định nghĩa:** Khi nhiều aspects apply cùng method — thứ tự quan trọng."},{"type":"code_block","code":"// Advice execution order (same join point):
// @Around (before proceed) → @Before → Method → @AfterReturning → @After → @Around (after proceed)

// Multiple aspects — order by @Order
@Aspect
@Order(1)  // Lower = higher priority = runs first (outer)
public class SecurityAspect { }

@Aspect
@Order(2)  // Runs second (inner)
public class LoggingAspect { }

// Execution: Security.before → Logging.before → Method → Logging.after → Security.after
// Like onion layers: outer aspect wraps inner aspect

// @Transactional internals:
// Spring creates TransactionInterceptor (AOP advice)
// Before method: begin transaction
// After method success: commit
// After method exception: rollback (for unchecked exceptions by default)

@Transactional
public void transfer(Long fromId, Long toId, BigDecimal amount) {
    // TransactionInterceptor:
    // 1. Get PlatformTransactionManager
    // 2. Begin transaction (or join existing)
    // 3. Execute method
    // 4. If RuntimeException/Error → rollback
    // 5. If checked exception → commit (default!)
    // 6. If success → commit
}

// ⚠️ Checked exceptions DON'T trigger rollback by default!
@Transactional(rollbackFor = Exception.class)  // Rollback for ALL exceptions
public void riskyOperation() throws IOException { }

// Propagation levels:
// REQUIRED (default): join existing or create new
// REQUIRES_NEW: always create new (suspend existing)
// NESTED: savepoint within existing transaction
