        return new MyLibraryClient(props.getApiKey(), props.getBaseUrl());
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: @ConfigurationProperties — Type-safe Configuration"},{"type":"paragraph","text":"**Định nghĩa:** Bind configuration properties vào Java objects — type-safe, validated, IDE-supported."},{"type":"code_block","code":"@ConfigurationProperties(prefix = "app.notification")
