@RestControllerAdvice
public class GlobalExceptionHandler extends ResponseEntityExceptionHandler {

    @ExceptionHandler(ResourceNotFoundException.class)
    public ProblemDetail handleNotFound(ResourceNotFoundException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
            HttpStatus.NOT_FOUND, ex.getMessage());
        problem.setTitle("Resource Not Found");
        problem.setType(URI.create("https://api.example.com/errors/not-found"));
        problem.setProperty("resourceType", ex.getResourceType());
        problem.setProperty("resourceId", ex.getResourceId());
        return problem;
    }

    @ExceptionHandler(BusinessRuleException.class)
    public ProblemDetail handleBusinessRule(BusinessRuleException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
            HttpStatus.UNPROCESSABLE_ENTITY, ex.getMessage());
        problem.setTitle("Business Rule Violation");
        problem.setProperty("rule", ex.getRule());
        problem.setProperty("context", ex.getContext());
        return problem;
    }

    // Validation errors — detailed field-level errors
    @Override
    protected ResponseEntity<Object> handleMethodArgumentNotValid(
            MethodArgumentNotValidException ex, HttpHeaders headers,
            HttpStatusCode status, WebRequest request) {
        ProblemDetail problem = ProblemDetail.forStatus(HttpStatus.BAD_REQUEST);
        problem.setTitle("Validation Failed");

        Map<String, String> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
            .collect(Collectors.toMap(
                FieldError::getField,
                fe -> fe.getDefaultMessage() != null ? fe.getDefaultMessage() : "Invalid",
                (a, b) -> a + "; " + b
            ));
        problem.setProperty("fieldErrors", fieldErrors);

        return ResponseEntity.badRequest().body(problem);
    }

    // Catch-all — NEVER expose internal details to client
    @ExceptionHandler(Exception.class)
    public ProblemDetail handleUnexpected(Exception ex) {
        logger.error("Unexpected error", ex);  // Full stack trace in logs
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
            HttpStatus.INTERNAL_SERVER_ERROR,
            "An unexpected error occurred");  // Generic message to client
        // KHÔNG include: stack trace, SQL queries, internal class names
        return problem;
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: API Design Best Practices"},{"type":"paragraph","text":"**Định nghĩa:** RESTful conventions, versioning, pagination, HATEOAS."},{"type":"code_block","code":"// URL design:
// GET    /api/v1/users          — list users
// GET    /api/v1/users/123      — get user
// POST   /api/v1/users          — create user
// PUT    /api/v1/users/123      — full update
// PATCH  /api/v1/users/123      — partial update
// DELETE /api/v1/users/123      — delete user
// GET    /api/v1/users/123/orders — nested resource

// API Versioning strategies:
// 1. URL path: /api/v1/users (most common, clear)
// 2. Header: Accept: application/vnd.example.v1+json
// 3. Query param: /api/users?version=1

// Pagination response:
@GetMapping
public ResponseEntity<PagedResponse<UserDto>> getUsers(
    @RequestParam(defaultValue = "0") int page,
    @RequestParam(defaultValue = "20") int size,
    @RequestParam(defaultValue = "createdAt,desc") String[] sort
) {
    Page<User> users = userService.findAll(
        PageRequest.of(page, size, Sort.by(parseSortOrders(sort)))
    );

    PagedResponse<UserDto> response = new PagedResponse<>(
        users.map(UserDto::from).getContent(),
        users.getNumber(),
        users.getSize(),
        users.getTotalElements(),
        users.getTotalPages(),
        users.isLast()
    );

    return ResponseEntity.ok(response);
}

// DTO validation — never trust client input
public record CreateUserRequest(
    @NotBlank @Size(min = 2, max = 100) String name,
    @NotBlank @Email String email,
    @NotNull @Past LocalDate birthDate,
    @Size(max = 500) String bio
) {}

// Response DTO — control what's exposed
public record UserDto(
    Long id,
    String name,
    String email,
    // KHÔNG include: password, internal IDs, audit fields
    LocalDateTime createdAt
) {
    public static UserDto from(User user) {
        return new UserDto(user.getId(), user.getName(),
            user.getEmail(), user.getCreatedAt());
    }
}","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Spring Data JPA — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Spring Data JPA abstracts database access. Senior cần hiểu N+1 problem, entity lifecycle, transaction isolation, optimistic/pessimistic locking, và query optimization."},{"type":"heading","level":2,"text":"Keyword: Entity Lifecycle & Persistence Context"},{"type":"paragraph","text":"**Định nghĩa:** JPA Entity có 4 states — Transient, Managed, Detached, Removed. Persistence Context (EntityManager) tracks managed entities."},{"type":"code_block","code":"// Entity states:
// Transient: new object, not in DB, not managed
User user = new User("An");  // Transient

// Managed: tracked by EntityManager, changes auto-synced to DB
userRepository.save(user);  // → Managed
user.setName("Bình");       // Dirty checking → auto UPDATE on flush

// Detached: was managed, now disconnected (after transaction ends)
// Changes NOT auto-synced
User detached = userRepository.findById(1L).get();
// Transaction ends → detached
detached.setName("Cường");  // NOT saved automatically
userRepository.save(detached);  // merge() → re-attach and save

// Removed: scheduled for deletion
userRepository.delete(user);  // → Removed → DELETE on flush

// Persistence Context = First-Level Cache
User u1 = userRepository.findById(1L).get();  // SQL SELECT
User u2 = userRepository.findById(1L).get();  // NO SQL — from cache
assert u1 == u2;  // Same object reference!

// Dirty checking — automatic change detection
@Transactional
public void updateUser(Long id, String newName) {
    User user = userRepository.findById(id).get();  // Managed
    user.setName(newName);  // Dirty
    // NO explicit save() needed!
    // On transaction commit → flush → UPDATE SQL generated
}

// Flush modes:
// AUTO (default): flush before queries and on commit
// COMMIT: flush only on commit
// entityManager.flush(); // Manual flush","language":"java"},{"type":"heading","level":2,"text":"Keyword: N+1 Problem & Solutions"},{"type":"paragraph","text":"**Định nghĩa:** Loading N child collections triggers N additional queries — most common JPA performance issue."},{"type":"code_block","code":"// N+1 Problem:
@Entity
public class Order {
    @OneToMany(mappedBy = "order", fetch = FetchType.LAZY)
    private List<OrderItem> items;
}

List<Order> orders = orderRepository.findAll();  // 1 query: SELECT * FROM orders
for (Order order : orders) {
    order.getItems().size();  // N queries: SELECT * FROM order_items WHERE order_id = ?
}
// Total: 1 + N queries!

// Solution 1: JOIN FETCH (JPQL)
@Query("SELECT o FROM Order o JOIN FETCH o.items WHERE o.status = :status")
List<Order> findByStatusWithItems(@Param("status") OrderStatus status);
// 1 query with JOIN — all data loaded

// ⚠️ JOIN FETCH + Pagination = memory issue
// Hibernate loads ALL results in memory, then paginates
// Warning: "HHH90003004: firstResult/maxResults specified with collection fetch"

// Solution 2: @EntityGraph
@EntityGraph(attributePaths = {"items", "items.product"})
List<Order> findByStatus(OrderStatus status);
// Generates LEFT JOIN FETCH

// Solution 3: @BatchSize — batch lazy loading
@Entity
public class Order {
    @OneToMany(mappedBy = "order")
    @BatchSize(size = 20)  // Load items for 20 orders at once
    private List<OrderItem> items;
}
// Instead of N queries → ceil(N/20) queries
// Global: spring.jpa.properties.hibernate.default_batch_fetch_size=20

// Solution 4: Projection — load only needed fields
public interface OrderSummary {
    Long getId();
    String getCustomerName();
    BigDecimal getTotalAmount();
    // No items loaded at all
}
List<OrderSummary> findByStatus(OrderStatus status);

// Solution 5: DTO Projection with JPQL
@Query("SELECT new com.example.dto.OrderDto(o.id, o.total, c.name) " +
       "FROM Order o JOIN o.customer c WHERE o.status = :status")
List<OrderDto> findOrderDtos(@Param("status") OrderStatus status);","language":"java"},{"type":"heading","level":2,"text":"Keyword: Transaction Isolation & Locking"},{"type":"paragraph","text":"**Định nghĩa:** Isolation levels và locking strategies cho concurrent data access."},{"type":"code_block","code":"// Isolation levels:
// READ_UNCOMMITTED: dirty reads possible (rarely used)
// READ_COMMITTED: no dirty reads (PostgreSQL default)
// REPEATABLE_READ: no dirty/non-repeatable reads (MySQL InnoDB default)
// SERIALIZABLE: no phantom reads (slowest)

@Transactional(isolation = Isolation.READ_COMMITTED)
public void transfer(Long fromId, Long toId, BigDecimal amount) { }

// Optimistic Locking — version-based, no DB locks
@Entity
public class Account {
    @Id private Long id;
    @Version private Long version;  // Auto-incremented on update
    private BigDecimal balance;
}

// Concurrent update:
// Thread A: read account (version=1), modify, save → version becomes 2
// Thread B: read account (version=1), modify, save → OptimisticLockException!
// Because version in DB (2) ≠ version in entity (1)

// Handle optimistic lock failure:
@Retryable(value = OptimisticLockException.class, maxAttempts = 3)
@Transactional
public void updateBalance(Long id, BigDecimal amount) {
    Account account = accountRepository.findById(id).orElseThrow();
    account.setBalance(account.getBalance().add(amount));
    // save() → checks version → retry if conflict
}

// Pessimistic Locking — DB-level locks
@Query("SELECT a FROM Account a WHERE a.id = :id")
@Lock(LockModeType.PESSIMISTIC_WRITE)  // SELECT ... FOR UPDATE
Optional<Account> findByIdForUpdate(@Param("id") Long id);

// PESSIMISTIC_READ: shared lock (multiple readers, no writers)
// PESSIMISTIC_WRITE: exclusive lock (no other readers or writers)
// PESSIMISTIC_FORCE_INCREMENT: exclusive lock + increment version

// Deadlock prevention:
// Always lock resources in consistent order
// Use timeouts: @QueryHints(@QueryHint(name = "javax.persistence.lock.timeout", value = "3000"))","language":"java"},{"type":"heading","level":2,"text":"Keyword: Query Optimization"},{"type":"paragraph","text":"**Định nghĩa:** Techniques để optimize JPA queries cho production workloads."},{"type":"code_block","code":"// 1. Use projections — load only needed columns
public interface UserNameOnly {
    String getName();
    String getEmail();
}
List<UserNameOnly> findByStatus(UserStatus status);
// SELECT name, email FROM users WHERE status = ?

// 2. Pagination — never load all records
Page<User> findByStatus(UserStatus status, Pageable pageable);
// SELECT * FROM users WHERE status = ? LIMIT 20 OFFSET 0

// 3. Specification — dynamic queries
public class UserSpecifications {
    public static Specification<User> hasName(String name) {
        return (root, query, cb) ->
            name == null ? null : cb.like(root.get("name"), "%" + name + "%");
    }

    public static Specification<User> hasStatus(UserStatus status) {
        return (root, query, cb) ->
            status == null ? null : cb.equal(root.get("status"), status);
    }
}

// Combine dynamically:
Specification<User> spec = Specification
    .where(UserSpecifications.hasName(nameFilter))
    .and(UserSpecifications.hasStatus(statusFilter));
Page<User> users = userRepository.findAll(spec, pageable);

// 4. Read-only transactions — skip dirty checking
@Transactional(readOnly = true)
public List<User> findAll() {
    return userRepository.findAll();
    // Hibernate skips dirty checking → faster
    // Some DBs route to read replica
}

// 5. Bulk operations — bypass entity lifecycle
@Modifying
@Query("UPDATE User u SET u.status = :status WHERE u.lastLogin < :date")
int deactivateInactiveUsers(@Param("status") UserStatus status,
                            @Param("date") LocalDateTime date);
// Direct SQL UPDATE — no entity loading, no dirty checking
// ⚠️ Bypasses persistence context cache — may cause stale data

// 6. Database indexing — most impactful optimization
// @Table(indexes = {
//     @Index(name = "idx_user_email", columnList = "email", unique = true),
//     @Index(name = "idx_user_status_created", columnList = "status, created_at")
// })","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Spring Security — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Spring Security cung cấp authentication và authorization. Senior cần hiểu filter chain architecture, security context propagation, JWT stateless auth, OAuth2 flows, và common vulnerabilities."},{"type":"heading","level":2,"text":"Keyword: Security Filter Chain Architecture"},{"type":"paragraph","text":"**Định nghĩa:** Spring Security = chain of servlet filters — mỗi filter xử lý một security concern."},{"type":"code_block","code":"// Filter chain order (simplified):
// 1. SecurityContextPersistenceFilter — load/save SecurityContext
// 2. CorsFilter — CORS headers
// 3. CsrfFilter — CSRF protection
// 4. LogoutFilter — handle /logout
// 5. UsernamePasswordAuthenticationFilter — form login
// 6. BasicAuthenticationFilter — HTTP Basic
// 7. BearerTokenAuthenticationFilter — OAuth2/JWT
// 8. ExceptionTranslationFilter — convert security exceptions to HTTP responses
// 9. FilterSecurityInterceptor — authorization check

// Custom filter chain:
@Bean
public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
    http
        .csrf(csrf -> csrf.disable())  // Disable for stateless API
        .sessionManagement(session ->
            session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
        .authorizeHttpRequests(auth -> auth
            .requestMatchers("/api/auth/**").permitAll()
            .requestMatchers("/api/admin/**").hasRole("ADMIN")
            .requestMatchers(HttpMethod.GET, "/api/public/**").permitAll()
            .anyRequest().authenticated()
        )
        .addFilterBefore(jwtFilter, UsernamePasswordAuthenticationFilter.class)
        .exceptionHandling(ex -> ex
            .authenticationEntryPoint((req, res, e) -> {
                res.setStatus(401);
                res.getWriter().write("{\"error\": \"Unauthorized\"}");
            })
            .accessDeniedHandler((req, res, e) -> {
                res.setStatus(403);
                res.getWriter().write("{\"error\": \"Forbidden\"}");
            })
        );

    return http.build();
}

// Multiple filter chains — different security for different paths
@Bean
@Order(1)
public SecurityFilterChain apiFilterChain(HttpSecurity http) throws Exception {
    http.securityMatcher("/api/**")  // Only for /api paths
        .csrf(csrf -> csrf.disable())
        .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS));
    return http.build();
}

@Bean
@Order(2)
public SecurityFilterChain webFilterChain(HttpSecurity http) throws Exception {
    http.securityMatcher("/**")  // Everything else
        .formLogin(Customizer.withDefaults());
    return http.build();
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: JWT Authentication — Production Implementation"},{"type":"paragraph","text":"**Định nghĩa:** Stateless authentication bằng signed tokens — không cần server-side session."},{"type":"code_block","code":"// JWT structure: header.payload.signature
// Header: {"alg": "HS256", "typ": "JWT"}
// Payload: {"sub": "user@example.com", "roles": ["USER"], "iat": ..., "exp": ...}
// Signature: HMAC-SHA256(base64(header) + "." + base64(payload), secret)

@Service
public class JwtService {
    private final SecretKey key;
    private final long accessTokenExpiry;
    private final long refreshTokenExpiry;

    public JwtService(@Value("${jwt.secret}") String secret,
                      @Value("${jwt.access-expiry:900000}") long accessExpiry,
                      @Value("${jwt.refresh-expiry:604800000}") long refreshExpiry) {
        this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
        this.accessTokenExpiry = accessExpiry;
        this.refreshTokenExpiry = refreshExpiry;
    }

    public String generateAccessToken(UserDetails user) {
        return Jwts.builder()
            .subject(user.getUsername())
            .claim("roles", user.getAuthorities().stream()
                .map(GrantedAuthority::getAuthority).toList())
            .issuedAt(new Date())
            .expiration(new Date(System.currentTimeMillis() + accessTokenExpiry))
            .signWith(key)
            .compact();
    }

    public String generateRefreshToken(UserDetails user) {
        return Jwts.builder()
            .subject(user.getUsername())
            .issuedAt(new Date())
            .expiration(new Date(System.currentTimeMillis() + refreshTokenExpiry))
            .signWith(key)
            .compact();
    }

    public Claims validateToken(String token) {
        return Jwts.parser()
            .verifyWith(key)
            .build()
            .parseSignedClaims(token)
            .getPayload();
    }
}

// JWT Filter
@Component
public class JwtAuthFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                     HttpServletResponse response,
                                     FilterChain chain) throws ServletException, IOException {
        String header = request.getHeader("Authorization");
        if (header == null || !header.startsWith("Bearer ")) {
            chain.doFilter(request, response);
            return;
        }

        try {
            String token = header.substring(7);
            Claims claims = jwtService.validateToken(token);
            String username = claims.getSubject();

            // Check if token is blacklisted (for logout)
            if (tokenBlacklist.isBlacklisted(token)) {
                chain.doFilter(request, response);
                return;
            }

            UserDetails userDetails = userDetailsService.loadUserByUsername(username);
            var auth = new UsernamePasswordAuthenticationToken(
                userDetails, null, userDetails.getAuthorities());
            auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
            SecurityContextHolder.getContext().setAuthentication(auth);
        } catch (JwtException e) {
            logger.debug("Invalid JWT: {}", e.getMessage());
            // Don't set authentication → request continues as anonymous
        }

        chain.doFilter(request, response);
    }
}

// Token refresh flow:
// 1. Client sends expired access token → 401
// 2. Client sends refresh token to /api/auth/refresh
// 3. Server validates refresh token → issue new access + refresh tokens
// 4. Old refresh token invalidated (rotation)

// JWT security considerations:
// - Store secret securely (env var, vault, not in code)
// - Short access token expiry (15 min)
// - Longer refresh token expiry (7 days)
// - Token blacklist for logout (Redis)
// - Use RS256 (asymmetric) for microservices (public key verification)
// - Never store sensitive data in JWT payload (it's base64, not encrypted)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Method Security & Authorization"},{"type":"paragraph","text":"**Định nghĩa:** Fine-grained authorization tại method level — SpEL expressions, custom permission evaluators."},{"type":"code_block","code":"@EnableMethodSecurity  // Spring Security 6+

@Service
public class DocumentService {

    // Role-based
    @PreAuthorize("hasRole('ADMIN')")
    public void deleteAll() { }

    // Permission-based with SpEL
    @PreAuthorize("hasAuthority('DOCUMENT_WRITE')")
    public Document create(Document doc) { }

    // Owner check — access method parameters
    @PreAuthorize("#userId == authentication.principal.id or hasRole('ADMIN')")
    public List<Document> findByUser(@Param("userId") Long userId) { }

    // Post-authorization — check return value
    @PostAuthorize("returnObject.owner == authentication.name")
    public Document findById(Long id) { }

    // Filter collections
    @PostFilter("filterObject.owner == authentication.name or hasRole('ADMIN')")
    public List<Document> findAll() { }

    // Custom permission evaluator
    @PreAuthorize("@documentSecurity.canEdit(#id, authentication)")
    public Document update(Long id, UpdateRequest request) { }
}

// Custom security evaluator
@Component("documentSecurity")
public class DocumentSecurityEvaluator {
    public boolean canEdit(Long documentId, Authentication auth) {
        Document doc = documentRepository.findById(documentId).orElse(null);
        if (doc == null) return false;
        String username = auth.getName();
        return doc.getOwner().equals(username)
            || auth.getAuthorities().stream()
                .anyMatch(a -> a.getAuthority().equals("ROLE_ADMIN"));
    }
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Common Security Vulnerabilities"},{"type":"paragraph","text":"**Định nghĩa:** OWASP Top 10 vulnerabilities và cách Spring Security bảo vệ."},{"type":"code_block","code":"// 1. SQL Injection — Spring Data JPA parameterized queries protect
// ❌ Vulnerable:
@Query(value = "SELECT * FROM users WHERE name = '" + name + "'", nativeQuery = true)
// ✅ Safe: parameterized
@Query("SELECT u FROM User u WHERE u.name = :name")

// 2. XSS — Spring escapes output by default (Thymeleaf)
// For REST APIs: Jackson escapes HTML in JSON by default

// 3. CSRF — Spring Security enables by default for session-based auth
// Disable for stateless JWT APIs: csrf.disable()

// 4. Broken Authentication
// - BCrypt password hashing (adaptive, salt built-in)
// - Account lockout after N failed attempts
// - Rate limiting on login endpoint

// 5. Sensitive Data Exposure
// - HTTPS everywhere (server.ssl.enabled=true)
// - Don't log passwords, tokens, PII
// - Don't include sensitive data in JWT payload
// - Secure headers:
http.headers(headers -> headers
    .contentSecurityPolicy(csp -> csp.policyDirectives("default-src 'self'"))
    .frameOptions(frame -> frame.deny())
    .httpStrictTransportSecurity(hsts -> hsts.maxAgeInSeconds(31536000))
);

// 6. Mass Assignment — don't bind request directly to entity
// ❌ @RequestBody User user → client can set role, id, etc.
// ✅ @RequestBody CreateUserRequest request → DTO with only allowed fields","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Spring Cloud & Microservices — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Microservices architecture giải quyết scalability nhưng tạo ra distributed systems complexity. Senior/Tech Lead cần hiểu trade-offs, patterns, failure modes, và khi nào KHÔNG nên dùng microservices."},{"type":"heading","level":2,"text":"Keyword: Microservices Trade-offs"},{"type":"paragraph","text":"**Định nghĩa:** Microservices không phải silver bullet — hiểu trade-offs trước khi adopt."},{"type":"code_block","code":"Monolith advantages:
✅ Simple development, testing, deployment
✅ Easy debugging (single process)
✅ No network latency between components
✅ ACID transactions
✅ Simple data consistency

Microservices advantages:
✅ Independent deployment & scaling
✅ Technology diversity per service
✅ Team autonomy (Conway's Law)
✅ Fault isolation
✅ Easier to understand individual services

Microservices costs:
❌ Network complexity (latency, failures, serialization)
❌ Distributed transactions (eventual consistency)
❌ Operational complexity (monitoring, tracing, deployment)
❌ Data consistency challenges
❌ Testing complexity (integration, contract tests)
❌ Debugging across services

When to use microservices:
- Large team (>20 developers) needing independent deployment
- Different scaling requirements per component
- Different technology requirements per component
- Organization structured around business capabilities

When NOT to use:
- Small team (<10 developers)
- Simple domain
- Tight coupling between components
- Starting a new project (start monolith, extract later)","language":"text"},{"type":"heading","level":2,"text":"Keyword: Service Communication Patterns"},{"type":"paragraph","text":"**Định nghĩa:** Synchronous (REST, gRPC) vs Asynchronous (messaging) — mỗi cái cho use case khác."},{"type":"code_block","code":"// Synchronous — REST with WebClient (reactive, non-blocking)
@Service
public class OrderService {
    private final WebClient userClient;

    public OrderService(WebClient.Builder builder) {
        this.userClient = builder.baseUrl("http://user-service").build();
    }

    public Mono<OrderDto> createOrder(CreateOrderRequest request) {
        return userClient.get()
            .uri("/api/users/{id}", request.userId())
            .retrieve()
            .onStatus(HttpStatusCode::is4xxClientError,
                response -> Mono.error(new UserNotFoundException(request.userId())))
            .bodyToMono(UserDto.class)
            .map(user -> processOrder(request, user));
    }
}

// Synchronous — OpenFeign (declarative, blocking)
@FeignClient(name = "user-service", fallback = UserClientFallback.class)
public interface UserClient {
    @GetMapping("/api/users/{id}")
    UserDto findById(@PathVariable Long id);
}

@Component
public class UserClientFallback implements UserClient {
    @Override
    public UserDto findById(Long id) {
        return new UserDto(id, "Unknown", "N/A");  // Fallback
    }
}

// Asynchronous — Event-driven with Spring Cloud Stream
@Service
public class OrderService {
    private final StreamBridge streamBridge;

    public Order createOrder(CreateOrderRequest request) {
        Order order = orderRepo.save(new Order(request));
        // Publish event — consumers process asynchronously
        streamBridge.send("order-events", new OrderCreatedEvent(order.getId()));
        return order;
    }
}

@Component
public class InventoryEventHandler {
    @Bean
    public Consumer<OrderCreatedEvent> handleOrderCreated() {
        return event -> {
            inventoryService.reserveItems(event.getOrderId());
        };
    }
}

// When to use sync vs async:
// Sync: need immediate response, simple request-reply
// Async: fire-and-forget, event notification, long processing
// Async: decoupling, buffering, reliability (message broker persists)","language":"java"},{"type":"heading","level":2,"text":"Keyword: Resilience Patterns"},{"type":"paragraph","text":"**Định nghĩa:** Patterns để handle failures trong distributed systems — Circuit Breaker, Retry, Bulkhead, Rate Limiter."},{"type":"code_block","code":"// Resilience4j — lightweight fault tolerance library

// Circuit Breaker — prevent cascade failures
@CircuitBreaker(name = "userService", fallbackMethod = "fallback")
public UserDto getUser(Long id) {
    return userClient.findById(id);
}

public UserDto fallback(Long id, Throwable t) {
    logger.warn("User service unavailable, using fallback", t);
    return new UserDto(id, "Unknown", "N/A");
}

// Circuit Breaker states:
// CLOSED → requests pass through, failures counted
// OPEN → requests blocked, fallback returned immediately
// HALF_OPEN → limited requests allowed to test recovery

// Retry — automatic retry with backoff
@Retry(name = "userService", fallbackMethod = "fallback")
public UserDto getUser(Long id) {
    return userClient.findById(id);
}

// Bulkhead — limit concurrent calls to prevent resource exhaustion
@Bulkhead(name = "userService", type = Bulkhead.Type.THREADPOOL)
public UserDto getUser(Long id) {
    return userClient.findById(id);
}

// Rate Limiter — limit request rate
@RateLimiter(name = "userService")
public UserDto getUser(Long id) {
    return userClient.findById(id);
}

// Configuration:
resilience4j:
  circuitbreaker:
    instances:
      userService:
        sliding-window-size: 10
        failure-rate-threshold: 50
        wait-duration-in-open-state: 10s
        permitted-number-of-calls-in-half-open-state: 3
  retry:
    instances:
      userService:
        max-attempts: 3
        wait-duration: 500ms
        exponential-backoff-multiplier: 2
        retry-exceptions:
          - java.io.IOException
          - java.util.concurrent.TimeoutException
  bulkhead:
    instances:
      userService:
        max-concurrent-calls: 10
        max-wait-duration: 500ms

// Decoration order matters:
// Retry → CircuitBreaker → Bulkhead → RateLimiter → Function
// Retry wraps CircuitBreaker: retry the circuit breaker call","language":"java"},{"type":"heading","level":2,"text":"Keyword: Distributed Data Patterns"},{"type":"paragraph","text":"**Định nghĩa:** Patterns cho data consistency across microservices — Saga, CQRS, Event Sourcing."},{"type":"code_block","code":"// Saga Pattern — distributed transaction as sequence of local transactions
// Each service: local transaction + publish event
// If any step fails: compensating transactions undo previous steps

// Choreography Saga (event-driven):
// OrderService: create order → publish OrderCreated
// PaymentService: listen OrderCreated → charge → publish PaymentCompleted
// InventoryService: listen PaymentCompleted → reserve → publish InventoryReserved
// OrderService: listen InventoryReserved → confirm order

// Compensation:
// PaymentService: charge fails → publish PaymentFailed
// OrderService: listen PaymentFailed → cancel order

// Orchestration Saga (central coordinator):
@Service
public class OrderSagaOrchestrator {
    public void createOrder(CreateOrderRequest request) {
        // Step 1: Create order (PENDING)
        Order order = orderService.create(request);

        try {
            // Step 2: Reserve payment
            paymentService.reserve(order.getId(), order.getTotal());

            // Step 3: Reserve inventory
            inventoryService.reserve(order.getId(), order.getItems());

            // Step 4: Confirm order
            orderService.confirm(order.getId());
        } catch (PaymentException e) {
            orderService.cancel(order.getId());  // Compensate
        } catch (InventoryException e) {
            paymentService.refund(order.getId());  // Compensate
            orderService.cancel(order.getId());    // Compensate
        }
    }
}

// CQRS — separate read and write models
// Write side: normalized, optimized for consistency
// Read side: denormalized, optimized for queries
// Sync via events: write → event → update read model

// Event Sourcing — store events, not current state
// Events: OrderCreated, ItemAdded, PaymentReceived, OrderShipped
// Current state = replay all events
// Benefits: complete audit trail, temporal queries, event replay
// Challenges: event schema evolution, eventual consistency, complexity

// Outbox Pattern — reliable event publishing
// Problem: save to DB + publish event = not atomic
// Solution: save event to outbox table in same transaction
// Background process reads outbox → publishes to message broker
@Transactional
public Order createOrder(CreateOrderRequest request) {
    Order order = orderRepo.save(new Order(request));
    outboxRepo.save(new OutboxEvent("OrderCreated", order.getId(), serialize(order)));
    return order;
    // Debezium or polling reads outbox → publishes to Kafka
}","language":"java"},{"type":"heading","level":2,"text":"Keyword: Observability — Logging, Metrics, Tracing"},{"type":"paragraph","text":"**Định nghĩa:** Three pillars of observability cho microservices — logs, metrics, distributed tracing."},{"type":"code_block","code":"// Distributed Tracing — Micrometer Tracing (Spring Boot 3+)
// Replaces Spring Cloud Sleuth
// Trace: entire request journey across services
// Span: single operation within a trace

// Auto-instrumented: RestTemplate, WebClient, @Async, messaging
// Log correlation: traceId and spanId in MDC
// [order-service,traceId=abc123,spanId=def456] Processing order...
// [payment-service,traceId=abc123,spanId=ghi789] Charging payment...
// Same traceId → same request chain

// Structured logging
logger.info("Order created", kv("orderId", order.getId()),
    kv("customerId", order.getCustomerId()),
    kv("total", order.getTotal()));
// JSON output: {"message":"Order created","orderId":123,"customerId":456,"total":99.99}

// Centralized logging: ELK Stack (Elasticsearch + Logstash + Kibana)
// or Grafana Loki

// Metrics: Micrometer → Prometheus → Grafana
// RED metrics per service:
// Rate: requests per second
// Errors: error rate
// Duration: response time percentiles (p50, p95, p99)

// Health checks for orchestration (Kubernetes):
// Liveness: is the process alive? (restart if not)
// Readiness: can it handle traffic? (remove from LB if not)
// Startup: has it finished starting? (don't check liveness until started)","language":"java"}]}

{"sections":[{"type":"heading","level":1,"text":"Real-world Project Patterns — Deep Dive"},{"type":"heading","level":2,"text":"Tổng Quan"},{"type":"paragraph","text":"Patterns và practices từ production systems. Senior/Tech Lead cần biết architecture decision records, testing pyramid, deployment strategies, và performance engineering."},{"type":"heading","level":2,"text":"Keyword: Architecture Decision Records (ADR)"},{"type":"paragraph","text":"**Định nghĩa:** Document architecture decisions — context, decision, consequences."},{"type":"code_block","code":"# ADR-001: Use PostgreSQL as primary database

## Status: Accepted

## Context
We need a relational database for our e-commerce platform.
Requirements: ACID transactions, JSON support, full-text search,
horizontal read scaling.

## Decision
Use PostgreSQL 16 with:
- Read replicas for query scaling
- JSONB columns for flexible product attributes
- Full-text search (tsvector) instead of Elasticsearch for simple cases

## Consequences
Positive:
- Strong ACID guarantees
- Rich JSON support reduces need for document DB
- Built-in FTS reduces infrastructure complexity

Negative:
- Write scaling limited to vertical (vs horizontal with NoSQL)
- Team needs PostgreSQL-specific knowledge
- JSONB queries less intuitive than document DB queries

## Alternatives Considered
- MySQL: less JSON support, less advanced features
- MongoDB: eventual consistency concerns for financial data
- DynamoDB: vendor lock-in, complex query patterns","language":"markdown"},{"type":"heading","level":2,"text":"Keyword: Testing Pyramid — Production Strategy"},{"type":"paragraph","text":"**Định nghĩa:** Unit → Integration → E2E — mỗi level có purpose và cost khác nhau."},{"type":"code_block","code":"// Testing pyramid:
//        /  E2E  \        Few, slow, expensive
//       / Contract \      API contract verification
//      / Integration \    DB, HTTP, messaging
//     /    Unit       \   Many, fast, cheap

// Unit Test — test business logic in isolation
@ExtendWith(MockitoExtension.class)
class OrderServiceTest {
    @Mock OrderRepository orderRepo;
    @Mock PaymentService paymentService;
    @Mock InventoryService inventoryService;
    @InjectMocks OrderService orderService;

    @Test
    void shouldRejectOrderWhenInsufficientStock() {
        when(inventoryService.checkStock(anyLong(), anyInt()))
            .thenReturn(false);

        assertThatThrownBy(() -> orderService.create(request))
            .isInstanceOf(InsufficientStockException.class)
            .hasMessageContaining("Product 123");

        verify(paymentService, never()).charge(any());
        verify(orderRepo, never()).save(any());
    }

    @Test
    void shouldCreateOrderAndChargePayment() {
        when(inventoryService.checkStock(anyLong(), anyInt())).thenReturn(true);
        when(orderRepo.save(any())).thenReturn(savedOrder);
        when(paymentService.charge(any())).thenReturn(paymentResult);

        OrderDto result = orderService.create(request);

        assertThat(result.status()).isEqualTo("CONFIRMED");
        verify(paymentService).charge(argThat(p ->
            p.getAmount().compareTo(new BigDecimal("99.99")) == 0));

        InOrder inOrder = inOrder(inventoryService, paymentService, orderRepo);
        inOrder.verify(inventoryService).checkStock(anyLong(), anyInt());
        inOrder.verify(orderRepo).save(any());
        inOrder.verify(paymentService).charge(any());
    }
}

// Integration Test — test with real DB, HTTP
@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
@AutoConfigureMockMvc
@Testcontainers  // Real PostgreSQL in Docker
class OrderControllerIntegrationTest {

    @Container
    static PostgreSQLContainer<?> postgres = new PostgreSQLContainer<>("postgres:16");

    @DynamicPropertySource
    static void configureProperties(DynamicPropertyRegistry registry) {
        registry.add("spring.datasource.url", postgres::getJdbcUrl);
        registry.add("spring.datasource.username", postgres::getUsername);
        registry.add("spring.datasource.password", postgres::getPassword);
    }

    @Autowired MockMvc mockMvc;

    @Test
    void shouldCreateAndRetrieveOrder() throws Exception {
        // Create
        String response = mockMvc.perform(post("/api/orders")
                .contentType(MediaType.APPLICATION_JSON)
                .content("""
                    {"productId": 1, "quantity": 2}
                    """))
            .andExpect(status().isCreated())
            .andExpect(jsonPath("$.id").isNumber())
            .andReturn().getResponse().getContentAsString();

        Long orderId = JsonPath.parse(response).read("$.id", Long.class);

        // Retrieve
        mockMvc.perform(get("/api/orders/{id}", orderId))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.status").value("PENDING"));
    }
}

// Contract Test — verify API contract between services
// Spring Cloud Contract or Pact
// Producer: defines contract, generates tests
// Consumer: uses contract stubs for testing","language":"java"},{"type":"heading","level":2,"text":"Keyword: Performance Engineering"},{"type":"paragraph","text":"**Định nghĩa:** Systematic approach to performance — profiling, benchmarking, optimization."},{"type":"code_block","code":"// 1. Measure first — don't optimize prematurely
// Tools: JMH (microbenchmark), JProfiler, async-profiler, Micrometer

// JMH Benchmark
@BenchmarkMode(Mode.Throughput)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
@State(Scope.Benchmark)
public class CollectionBenchmark {
    @Benchmark
    public void arrayListIteration(Blackhole bh) {
        for (String s : arrayList) bh.consume(s);
    }

    @Benchmark
    public void linkedListIteration(Blackhole bh) {
        for (String s : linkedList) bh.consume(s);
    }
}

// 2. Common performance optimizations:

// Database:
// - Add indexes for WHERE, JOIN, ORDER BY columns
// - Use EXPLAIN ANALYZE to verify query plans
// - Connection pooling (HikariCP default in Spring Boot)
// - N+1 query elimination (JOIN FETCH, @BatchSize)
// - Read replicas for read-heavy workloads

// Caching:
@Cacheable(value = "products", key = "#id", unless = "#result == null")
public Product findById(Long id) { }

@CacheEvict(value = "products", key = "#product.id")
public Product update(Product product) { }

@CacheEvict(value = "products", allEntries = true)
public void clearCache() { }

// Cache levels:
// L1: In-process (Caffeine) — fastest, per-instance
// L2: Distributed (Redis) — shared across instances
// Strategy: L1 for hot data, L2 for shared data

// Async processing:
@Async("taskExecutor")
public CompletableFuture<Report> generateReport(Long userId) {
    // Runs in separate thread pool — doesn't block request
    return CompletableFuture.completedFuture(buildReport(userId));
}

@Bean
public TaskExecutor taskExecutor() {
    ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
    executor.setCorePoolSize(5);
    executor.setMaxPoolSize(20);
    executor.setQueueCapacity(100);
    executor.setThreadNamePrefix("async-");
    executor.setRejectedExecutionHandler(new CallerRunsPolicy());
    return executor;
}

// 3. JVM Tuning:
// -Xms2g -Xmx2g (set min=max to avoid resize)
// -XX:+UseG1GC (default Java 11+)
// -XX:MaxGCPauseMillis=200
// -XX:+UseStringDeduplication (G1 only)
// -XX:+HeapDumpOnOutOfMemoryError
// -XX:HeapDumpPath=/var/log/heapdump.hprof","language":"java"},{"type":"heading","level":2,"text":"Keyword: Common Anti-patterns — Senior Perspective"},{"type":"paragraph","text":"**Định nghĩa:** Design và implementation mistakes phổ biến trong production systems."},{"type":"code_block","code":"// 1. Distributed Monolith — worst of both worlds
// Microservices that are tightly coupled, must deploy together
// Fix: ensure services can deploy and fail independently

// 2. Shared Database — coupling through data
// Multiple services access same tables
// Fix: database per service, API for data access

// 3. Chatty Services — too many inter-service calls
// Order service calls User, Product, Inventory, Payment for every request
// Fix: aggregate data, cache, async events, BFF pattern

// 4. Anemic Domain Model — entities without behavior
// ❌ All logic in services, entities are just data holders
@Entity
public class Order {
    private BigDecimal total;
    private OrderStatus status;
    // Only getters/setters
}

@Service
public class OrderService {
    public void addItem(Order order, Product product, int qty) {
        // All logic here — Order is just a data bag
    }
}

// ✅ Rich Domain Model — entities encapsulate behavior
@Entity
public class Order {
    public void addItem(Product product, int quantity) {
        validateNotFinalized();
        items.add(new OrderItem(product, quantity));
        recalculateTotal();
    }

    public void confirm() {
        if (items.isEmpty()) throw new EmptyOrderException();
        this.status = OrderStatus.CONFIRMED;
    }
}

// 5. God Class / God Service — too many responsibilities
// Fix: SRP, extract services, domain-driven design

// 6. Premature Optimization
// "We might need to handle 1M requests/sec"
// Fix: measure first, optimize bottlenecks, YAGNI

// 7. Resume-Driven Development
// Using Kafka, Kubernetes, microservices for a CRUD app
// Fix: choose technology based on requirements, not hype

// 8. Ignoring Observability
// No logging, no metrics, no tracing → blind in production
// Fix: structured logging, Micrometer metrics, distributed tracing from day 1","language":"java"}]}
